-- CAT_QUELTHALAS
IMAGOdb.npcs.CAT_QUELTHALAS["lorthemar_theron"].name = "Lor'themar Theron"
IMAGOdb.npcs.CAT_QUELTHALAS["lorthemar_theron"].race = "Blood Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["lorthemar_theron"].lore =
[[
A ranger at heart, Lor'themar Theron didn't choose to lead the blood elves. When Quel'thalas fell to the Scourge in the Third War he was appointed, in absence of any other surviving candidates, to serve the fallen kingdom as regent by Prince Kael'thas.
He was forced to make difficult decisions, such as allying the blood elves with the Horde, exiling the high elves to combat unrest, and leading the battle against Kael'thas after the prince's betrayal. Lor'themar's pragmatism and strategic cunning made him an inspiring leader nontheless, commanding respect from friends and foes alike. 
A staunch advocate for peace, Lor'themar serves now both as regent lord of Quel'thalas and as a member of the Horde's ruling council. His loyality lies first and foremost with his people.

Now, with Quel'thalas in peril once again, he will stop at nothing to defend his people and his city against the encroaching forces of the void.]]
IMAGOdb.npcs.CAT_QUELTHALAS["lorthemar_theron"].zones = {"Amirdrassil", "Harandar", "Eversong Woods", "Isle of Quel'Danas", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["lorthemar_theron"].source = "warcraft.wiki.gg/wiki/Lor'themar_Theron"
IMAGOdb.npcs.CAT_QUELTHALAS["lorthemar_theron"].timeline = {
    {era = "WC2", text = "Successfully defended Silvermoon under Sylvanas Windrunner's command and was promoted to ranger lord."},
    {era = "WC3", text = "After surviving Quel'thalas' destruction, Prince Kael'Thas promoted him to regent lord. He successfully reclaimed Silvermoon from the Scourge"},
    {era = "TBC", text = "He led the blood elves to join the Horde, made the decision to exile the high elves, and deposed of Kael'thas after his treachery. After the civil war, Lor'themar remained as regent lord."},
    {era = "WotLK", text = "Reluctantly agreed to send elven troops to Northrend to aid the Horde in the battle against the Lich King and helped recover the ancient weapon Quel'delar."},
    {era = "Pre-MoP", text = "Refused to personally take part in the attack on Theramore, drawing the ire of Garrosh Hellscream."},
    {era = "MoP", text = "Negotiated with King Varian Wrynn to rejoin the Alliance after heavily disagreeing with Garrosh's leadership. After the purge of Dalaran, he remained in the Horde and played a key part in the rebellion against Garrosh Hellscream."},
    {era = "BfA", text = "Successfully invited the nightborne of Suramar to join the Horde. He later personally led the Horde forces in the campaign against Queen Aszhara and joined the rebellion against Sylvanas Windrunner. After the Fourth War he joined the newly-formed Horde council as one of its leaders."},
    {era = "Pre-DF", text = "Married Thalyssra and invited both Horde and Alliance leaders to the wedding in a show of support for peace between the factions."},
    {era = "DF", text = "Joined in the defense of Amirdrassil."},
    {era = "Midnight", text = "Led the blood elf forces in Silvermoon's defense against the Void."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["erste_arkanistin_thalyssra"].name = "First Arcanist Thalyssra"
IMAGOdb.npcs.CAT_QUELTHALAS["erste_arkanistin_thalyssra"].race = "Nightborne"
IMAGOdb.npcs.CAT_QUELTHALAS["erste_arkanistin_thalyssra"].lore = "First Arcanist Thalyssra is the leader of the nightborne elves. Once exiled from her home city of Suramar by a corrupt ruler, First Arcanist Thalyssra has liberated the shal'dorei people of their addiction to their Nightwell's power, stepping up to lead after the sacking of Suramar. She now rules her people arm in arm with Lor'themar Theron's blood elves, uniting the two cultures through unity in the Horde, and the unity of their marriage"
IMAGOdb.npcs.CAT_QUELTHALAS["erste_arkanistin_thalyssra"].zones = {"Amirdrassil", "The Eternal Palace", "Isle of Quel'Danas", "Silvermoon City", "Suramar"}
IMAGOdb.npcs.CAT_QUELTHALAS["erste_arkanistin_thalyssra"].source = ""
IMAGOdb.npcs.CAT_QUELTHALAS["erste_arkanistin_thalyssra"].timeline = {
    {era = "Legion", text = "Thalyssra was exiled from Suramar for opposing the Legion and sent a magical distress signal that was intercepted by Khadgar, allowing her to establish a resistance in Shal’Aran. With  allies, she freed the nightborne from their dependence on the Nightwell, and led a joint assault with Horde and Alliance forces to liberate Suramar. After becoming leader, she chose to let the Nightwell fade and pledged the nightborne to the Horde."},
    {era = "BfA", text = "During the Fourth War, Thalyssra assisted the Horde in breaking the Zandalari out of Stormwind, assisted the Horde fleet in Nazjatar, and later supported the rebellion against Sylvanas Windrunner. After N’Zoth’s defeat, she joined the Horde Council."},
    {era = "SL", text = "Thalyssra witnessed the ritual to open the doorway to the Maw at the Frozen Throne within Icecrown Citadel. Following the defeat of the Jailer, Thalyssra and Lor'themar briefly traveled to Oribos in the Shadowlands to attend Sylvanas' trial."},
    {era = "DF", text = "Thalyssra saw the Horde expedition depart to the Dragon Isles. She and her now-husband, Lor’themar Theron, mused on how they were fortunate to have had a brief respite and playfully bantered about who proposed to whom. Thalyssra eventually joined Alexstrasza and her allies to defend the growing Amirdrassil from Fyrakk the Blazing in the Emerald Dream."},
    {era = "Midnight", text = "Thalyssra stayed in Sunfury Spire in Silvermoon until the Sunwell’s corruption. She requested aid from Suramar City, but when no response came, she went to investigate and uncovered Twilight’s Blade infiltrators. After restoring order, she led the nightborne army to Silvermoon to aid in the assault on the Devouring Host."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["lady_liadrin"].name = "Lady Liadrin"
IMAGOdb.npcs.CAT_QUELTHALAS["lady_liadrin"].race = "Blood Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["lady_liadrin"].lore = "Once a devoted priestess of the Light, Lady Liadrin lost her faith after the Scourge decimated Silvermoon. She became the first Blood Knight, initially bending the Light to her will by siphoning the naaru M'uru. Through the restoration of the Sunwell, she found redemption and true devotion. Today, as Matriarch of the Blood Knights, she is one of the most noble champions of the Army of the Light, standing unwavering between her homeland and the endless hunger of the Void."
IMAGOdb.npcs.CAT_QUELTHALAS["lady_liadrin"].zones = {"Atal'Aman", "Dornogal", "Eversong Woods", "Isle of Quel'Danas", "Orgrimmar", "Parhelion Plaza", "Silvermoon City", "Stormwind City", "Zul'Aman"}
IMAGOdb.npcs.CAT_QUELTHALAS["lady_liadrin"].source = "warcraft.wiki.gg/wiki/Lady_Liadrin"
IMAGOdb.npcs.CAT_QUELTHALAS["lady_liadrin"].timeline = {
    {era = "WC3", text = "Survived the Scourge invasion of Quel'Thalas, lost her faith, and abandoned the priesthood to take up the sword."},
    {era = "TBC", text = "Founded the Blood Knights, turned against Kael'thas, pledged loyalty to the Sha'tar, and helped purify the Sunwell."},
    {era = "WoD", text = "Led the Sunsworn in Auchindoun in the battle against the Shadow Council and the Burning Legion."},
    {era = "Legion", text = "Became a Highlord of the Silver Hand and fought alongside the Army of the Light on the demon world of Argus."},
    {era = "BfA", text = "Recruited the Nightborne into the Horde and commanded Horde forces at the Arathi Highlands Warfront."},
    {era = "Midnight", text = "Coordinates the forces of the Light and the Blood Knights to defend Quel'Thalas against Xal'atath's Void powers."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["grand_magister_rommath"].name = "Grand Magister Rommath"
IMAGOdb.npcs.CAT_QUELTHALAS["grand_magister_rommath"].race = "Blood Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["grand_magister_rommath"].lore = "As the Grand Magister of Quel'Thalas and leader of the Magisters, Rommath is the undisputed master of the arcane arts in Silvermoon. He was once a loyal companion of Kael'thas Sunstrider in Outland, but returned home to save his people from magical starvation. He harbors a deep, unforgiving hatred for the Kirin Tor, who once sentenced the blood elves to death. Pragmatic, sharp-tongued, and fiercely loyal to the Sin'dorei, he unleashes the full might of his Magisters in Midnight to repel the Void invasion. His presence in Orgrimmar and deep within the Twilight Highlands shows he is willing to harness even the most dangerous arcane or shadow knowledge to save his homeland."
IMAGOdb.npcs.CAT_QUELTHALAS["grand_magister_rommath"].zones = {"Eversong Woods", "Orgrimmar", "Twilight Highlands", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["grand_magister_rommath"].source = "warcraft.wiki.gg/wiki/Grand_Magister_Rommath"
IMAGOdb.npcs.CAT_QUELTHALAS["grand_magister_rommath"].timeline = {
    {era = "WC3", text = "Escaped the dungeons of Dalaran with Kael'thas and followed him to the shattered world of Outland."},
    {era = "TBC", text = "Returned to Quel'Thalas, helped rebuild Silvermoon, and taught the blood elves how to siphon magic."},
    {era = "MoP", text = "Rescued Aethas Sunreaver and other blood elves during Jaina Proudmoore's bloody Purge of Dalaran."},
    {era = "Legion", text = "Defended Quel'Thalas against the Burning Legion and reluctantly supported the Tirisgarde."},
    {era = "BfA", text = "Played a key role in recruiting the Nightborne as new allies of the Horde."},
    {era = "Midnight", text = "Coordinates the arcane defense in Eversong Woods and seeks war-winning resources in the Twilight Highlands."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["halduron_brightwing"].name = "Halduron Brightwing"
IMAGOdb.npcs.CAT_QUELTHALAS["halduron_brightwing"].race = "Blood Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["halduron_brightwing"].lore =
[[
The current Ranger-General of Silvermoon and best friend of Lor'themar Theron, Halduron Brightwing keeps the borders of his homeland safe. He has served his people for decades, standing against every threat thrown at him with unwavering courage – from Amani troll invaders to the horrifying undead of the Scourge.
    
Despite the deadly fervor he shows his enemies on the field of battle, Halduron is known to his friends as a tolerant and bright-spirited man with a good eye for detail.]]
IMAGOdb.npcs.CAT_QUELTHALAS["halduron_brightwing"].zones = {"The Den", "Harandar", "Eversong Woods", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["halduron_brightwing"].source = "Cadash"
IMAGOdb.npcs.CAT_QUELTHALAS["halduron_brightwing"].timeline = {
    {era = "WC2", text = "Fought against the Amani trolls, and managed to capture their leader, Zul'jin."},
    {era = "WC3", text = "Survived the Scourge attack and was named Ranger-general after Sylvanas' death. Began to drive out the remaining Scourge forces from the ruined Silvermoon City."},
    {era = "TBC", text = "Strongly opposed the creation of the Blood Knights. Successfully negotiated the admittance of the Blood Elves into the Horde as an envoy in Orgrimmar."},
    {era = "WotLK", text = "Oversaw the construction of defenses for the renewed Sunwell."},
    {era = "Cata", text = "Rooted out a reforming Amani force, forming a brief alliance with Vereesa Windrunner in the process."},
    {era = "MoP", text = "Fought the rising Zandalari threat on the Isle of Thunder."},
    {era = "Legion", text = "Joined the Unseen Path and helped to defeat Hakkar the Houndmaster."},
    {era = "Pre-DF", text = "Attended Lor'themar and Thalyssra's wedding as groomsman."},
    {era = "Midnight", text = "Halduron was the first to notice the threat of the Lightbloom and ventured into Harandar with Orweyna. Securing a tentative alliance with the Haranir, Halduron managed to keep the Lightbloom in check and strengthened Silvermoon's defenses."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["alleria_windrunner"].name = "Alleria Windrunner"
IMAGOdb.npcs.CAT_QUELTHALAS["alleria_windrunner"].race = "Void Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["alleria_windrunner"].lore = "The eldest of the Windrunner sisters and a legend among elves. After millennia of absence and endless war in the Twisting Nether, Alleria absorbed the essence of a dark naaru, becoming the first Void Elf. She carries the constant temptation and whispers of the shadows within her. In Midnight, she returns to her homeland to unite the splintered elves in the defense of Quel'Thalas and personally confront her nemesis, Xal'atath, on the frontlines."
IMAGOdb.npcs.CAT_QUELTHALAS["alleria_windrunner"].zones = {"The Void Spire", "Voidstorm"}
IMAGOdb.npcs.CAT_QUELTHALAS["alleria_windrunner"].source = "warcraft.wiki.gg/wiki/Alleria_Windrunner"
IMAGOdb.npcs.CAT_QUELTHALAS["alleria_windrunner"].timeline = {
    {era = "WC2", text = "Led the elven rangers in the Second War and traveled with the Alliance Expedition through the Dark Portal."},
    {era = "Legion", text = "Absorbed the power of the dark naaru L'ura on Argus and mastered the energies of the Void."},
    {era = "BfA", text = "Led the ren'dorei (Void Elves) as new allies into the ranks of the Alliance."},
    {era = "TWW", text = "Hunted Xal'atath as her personal nemesis through Khaz Algar to save Azeroth from falling."},
    {era = "Midnight", text = "Fights in the most dangerous zones of the Voidstorm and the Void Spire for the survival of Quel'Thalas."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["vereesa_windrunner"].name = "Vereesa Windrunner"
IMAGOdb.npcs.CAT_QUELTHALAS["vereesa_windrunner"].race = "High Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["vereesa_windrunner"].lore = "The youngest of the Windrunner sisters and the resolute leader of the Silver Covenant. Unlike her sisters, Vereesa remained true to the path of the High Elves and established deep roots within the Alliance. After the painful loss of her husband Rhonin at Theramore, she dedicated her life to protecting Azeroth and training her rangers. In Midnight, she returns to Quel'Thalas to defend her homeland against the Void and face the painful legacy of her family."
IMAGOdb.npcs.CAT_QUELTHALAS["vereesa_windrunner"].zones = {"Eversong Woods", "Isle of Quel'Danas", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["vereesa_windrunner"].source = "warcraft.wiki.gg/wiki/Vereesa_Windrunner"
IMAGOdb.npcs.CAT_QUELTHALAS["vereesa_windrunner"].timeline = {
    {era = "Pre-Classic", text = "Fought in Grim Batol during the events of 'Day of the Dragon', where she met her future husband, Rhonin."},
    {era = "WotLK", text = "Founded the Silver Covenant in Dalaran to limit the influence of the blood elves within the Kirin Tor."},
    {era = "MoP", text = "Supported Jaina Proudmoore during the bloody Purge of Dalaran following the destruction of Theramore."},
    {era = "Legion", text = "Joined the Unseen Path and was reunited with her sister Alleria after over a thousand years."},
    {era = "Midnight", text = "Leads the Silver Covenant rangers in the defense of Silvermoon and the Isle of Quel'Danas."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["shandris_feathermoon"].name = "Shandris Feathermoon"
IMAGOdb.npcs.CAT_QUELTHALAS["shandris_feathermoon"].race = "Night Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["shandris_feathermoon"].lore = [[Orphaned during the War of the Ancients, Shandris has known battle for almost as long as she has lived. Adopted by Tyrande Whisperwind and Malfurion Stormrage, she trained as a huntress and has since become one of the most formidable archers on Azeroth.
Shandris has led the night elven and Alliance forces as high general of the Sentinel army on more than one occasion, and after being on the front lines of defense of the new world tree Amirdrassil, she now leads the Night Elves as their ruler.
Highly protective of the people she holds dear – even venturing into the realms of death itself to rescue her mother – Shandris nowadays wants peace most of all. ]]
IMAGOdb.npcs.CAT_QUELTHALAS["shandris_feathermoon"].zones = {"Amirdrassil", "Harandar", "Silvermoon City", "Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_QUELTHALAS["shandris_feathermoon"].source = "Cadash - IMAGO Community"
IMAGOdb.npcs.CAT_QUELTHALAS["shandris_feathermoon"].timeline = {
    {era = "Ancient History", text = "Was orphaned during the first invasion of the Burning Legion, adopted by Tyrande Whisperwind."},
    {era = "WC3", text = "Fought the Burning Legion and Archimonde himself in Ashenvale and Mount Hyjal."},
    {era = "Classic", text = "Was promoted to high general of the Sentinels."},
    {era = "Cata", text = "Kept Kalimdor safe from Naga threats and began the admission of the Worgen to the Sentinels. Helped defend Ashenvale from Garrosh Hellscream's invasion."},
    {era = "Pre-MoP", text = "Tried and failed to defend Theramore from the Horde."},
    {era = "Legion", text = "Joined the Unseen Path and helped defeat Hakkar the Houndmaster."},
    {era = "Pre-BfA", text = "Drove off Horde invaders in Darkshore but couldn't arrive in time to help defend Teldrassil."},
    {era = "BfA", text = " Coordinated the Alliance war effort on Zandalar. Helped Tyrande to become the Night Warrior and fought back against the Horde in Darkshore once more. She led Alliance forces against Queen Aszhara after the battle in her homeland was won."},
    {era = "SL", text = "Followed her mother Tyrande into the Shadowlands and freed her of the Night Warrior's curse."},
    {era = "DF", text = "Defended Amirdrassil from Fyrakk's flames and worked together with the Forsaken in a first attempt at letting the Fourth War rest. Afterwards, Tyrande and Malfurion named her as the new leader of the Night Elves."},
    {era = "Midnight", text = "Shandris has aided the Blood Elves against the threat of the Void and helped to create the Dawnwell."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["aethas_sunreaver"].name = "Archmage Aethas Sunreaver"
IMAGOdb.npcs.CAT_QUELTHALAS["aethas_sunreaver"].race = "Blood Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["aethas_sunreaver"].lore = "Archmage Aethas Sunreaver looks back on a turbulent political career. For a long time, as the leader of the blood elven magi in the Kirin Tor, he tried to build a bridge between Dalaran and Silvermoon. After the tragic destruction of Dalaran in Khaz Algar, he turned his back on the old order of the magi. In Midnight, he has returned to Quel'Thalas to defend his homeland against the Void. When the alliance with the Silver Covenant is debated at the war table in Silvermoon, Aethas is initially strictly against it. Only when Vereesa Windrunner presents him with the ashes of fallen Sunreavers and ancient relics as an offering of peace does he relent in the face of impending annihilation."
IMAGOdb.npcs.CAT_QUELTHALAS["aethas_sunreaver"].zones = {"Eversong Woods", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["aethas_sunreaver"].source = "warcraft.wiki.gg/wiki/Aethas_Sunreaver"
IMAGOdb.npcs.CAT_QUELTHALAS["aethas_sunreaver"].timeline = {
    {era = "WotLK", text = "Founded the Sunreavers in Dalaran, securing a sanctuary for the Horde within the magi city."},
    {era = "MoP", text = "Was imprisoned as a traitor during the bloody Purge of Dalaran by Jaina Proudmoore and fled to Silvermoon."},
    {era = "TWW", text = "Survived the crash of Dalaran in Khaz Algar and renounced the arrogant, global political meddling of the Kirin Tor."},
    {era = "Midnight", text = "Defends Silvermoon at the war table and overcomes his hatred of the Silver Covenant to save Quel'Thalas."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["salandria"].name = "Salandria"
IMAGOdb.npcs.CAT_QUELTHALAS["salandria"].race = "Blood Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["salandria"].lore = "Salandria spent her early childhood as a war orphan in Shattrath. Even then, she showed a strong connection to the Holy Light and immense ambition. She was eventually adopted by Lady Liadrin, matriarch of the Blood Knights, and trained as a powerful paladin in Silvermoon. Even in the Caverns of Time, the bronze dragonflight sensed that she would one day play a massive role in the fate of Azeroth. In Midnight, the former orphan stands on the front lines as an adult, battle-ready Blood Knight. She defends Quel'Thalas, her mentor Liadrin, and her people's legacy with iron determination against the encroaching Void."
IMAGOdb.npcs.CAT_QUELTHALAS["salandria"].zones = {"Eversong Woods", "Isle of Quel'Danas", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["salandria"].source = "warcraft.wiki.gg/wiki/Salandria"
IMAGOdb.npcs.CAT_QUELTHALAS["salandria"].timeline = {
    {era = "TBC", text = "Grew up as an orphan in Shattrath and was cared for by Horde adventurers during Children's Week. The guards of the Caverns of Time attempted to attack her then due to ominous future deeds."},
    {era = "WotLK", text = "Left a copper coin in the Dalaran fountain with the wish: 'Someday I'll be more powerful than all these mages!'"},
    {era = "SL", text = "Emerged for the first time as an adult Blood Knight in Patch 9.2.5, helping the blood elves defend Tranquillien against the San'layn Vorath."},
    {era = "Midnight", text = "Defends Silvermoon, Eversong Woods, and Quel'Danas as a battle-hardened Blood Knight of the coalition."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["magister_umbric"].name = "Magister Umbric"
IMAGOdb.npcs.CAT_QUELTHALAS["magister_umbric"].race = "Void Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["magister_umbric"].lore = "Magister Umbric is the wise and pragmatic leader of the ren'dorei (Void Elves). Driven by the desire to defend Quel'Thalas at all costs, he once researched forbidden Void magic, which led to his exile by Grand Magister Rommath. In exile, he almost fell victim to the nether-prince Durzaan but was saved at the last moment by Alleria Windrunner. Although he now serves the Alliance, he has never lost his love for his homeland. Most recently, he led a research expedition to K'aresh until Arator the Redeemer sought him out in Tazavesh, warning him of the impending danger to Silvermoon. Without hesitation, Umbric gathered his people. In Midnight, despite the bitter past, he returns to his homeland, turning his mastery over the Void against Xal'atath's forces."
IMAGOdb.npcs.CAT_QUELTHALAS["magister_umbric"].zones = {"Amirdrassil", "The Voidspire", "Eversong Woods", "Isle of Quel'Danas", "Voidstorm", "Twilight Highlands", "Silvermoon City", "Stormwind City", "Magister's Terrace"}
IMAGOdb.npcs.CAT_QUELTHALAS["magister_umbric"].source = "Quest: Die Geisterlande"
IMAGOdb.npcs.CAT_QUELTHALAS["magister_umbric"].timeline = {
    {era = "BfA", text = "Was exiled from Silvermoon for his Void research, transformed by the Void in the Ghostlands, and saved by Alleria Windrunner."},
    {era = "BfA", text = "Pledged loyalty to the Alliance and led the Void Elf forces during the Fourth War in crucial acts of sabotage in Zandalar."},
    {era = "TWW", text = "Established the Shan'dorah camp on K'aresh and was mobilized in Tazavesh by Arator after the defeat of Dimensius to save Silvermoon."},
    {era = "Midnight", text = "Returns to Quel'Thalas to defend the Sunwell and operates deep within Void-distorted zones like the Voidspire."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["lady_darkglen"].name = "Lady Darkglen"
IMAGOdb.npcs.CAT_QUELTHALAS["lady_darkglen"].race = "Undead (Dark Ranger)"
IMAGOdb.npcs.CAT_QUELTHALAS["lady_darkglen"].lore = "Lady Darkglen is a fearsome commander of the Dark Rangers and a cold, loyal defender of Quel'Thalas. As an undead who once served under the banner of Sylvanas Windrunner, she unambiguously chose to remain loyal to her true homeland after the Banshee Queen's betrayal. Already during the Fourth War, she delivered devastating strikes against the Alliance at the Darkshore warfront. In Midnight, she brings her deadly, pragmatic precision back home. She operates ruthlessly in the Voidstorm and coordinates defenses from Silvermoon City, where her arrows no longer seek night elves, but silently pierce the monstrous entities of the Void."
IMAGOdb.npcs.CAT_QUELTHALAS["lady_darkglen"].zones = {"Voidstorm", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["lady_darkglen"].source = "Quest: Die Schlacht an der Dunkelküste"
IMAGOdb.npcs.CAT_QUELTHALAS["lady_darkglen"].timeline = {
    {era = "BfA", text = "Served as a high-ranking commander of the Dark Rangers at the Darkshore Warfront against the warriors of Elune."},
    {era = "Midnight", text = "Leads the ranks of the Dark Rangers on the front lines in the Voidstorm and Silvermoon City to repel the Void invasion."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["riftblade_maella"].name = "Riftblade Maella"
IMAGOdb.npcs.CAT_QUELTHALAS["riftblade_maella"].race = "Void Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["riftblade_maella"].lore = "Riftblade Maella is a deadly melee combatant of the ren'dorei and part of the absolute vanguard of Magister Umbric's forces. As a Riftblade, she masters the art of fusing physical martial prowess with the unstable magic of the Telogrus Rift to slice through space and disorient her foes. The fact that the Void Elves are defending their old homeland of Quel'Thalas in Midnight is a matter of honor and survival for Maella. Her deployments in the Voidspire and at the center of the deadly Voidstorm show that she fearlessly fights where the corruption of the Void is thickest. She ruthlessly uses pure darkness as a weapon against the Void itself, defending Silvermoon City with ice-cold precision."
IMAGOdb.npcs.CAT_QUELTHALAS["riftblade_maella"].zones = {"The Voidspire", "Voidstorm", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["riftblade_maella"].source = "Quest: Der Telogrusriss"
IMAGOdb.npcs.CAT_QUELTHALAS["riftblade_maella"].timeline = {
    {era = "BfA", text = "Was transformed in the Ghostlands and trained as a Riftblade in the Telogrus Rift to master the Void on the battlefield."},
    {era = "Midnight", text = "Leads the melee vanguard of the ren'dorei in the Voidstorm and the Voidspire to protect the Sunwell."},
}

IMAGOdb.npcs.CAT_QUELTHALAS["astalor_bloodsworn"].name = "Astalor Bloodsworn"
IMAGOdb.npcs.CAT_QUELTHALAS["astalor_bloodsworn"].race = "Blood Elf"
IMAGOdb.npcs.CAT_QUELTHALAS["astalor_bloodsworn"].lore =
[[
Co-founder of the Blood Knights of Silvermoon, the mage Astalor Bloodsworn has always searched for creative ways to aid his people. When Kael'thas sent the captured Naaru M'uru back to Silvermoon, it was Astalor who advised to not merely feast upon the holy creature, but instead to siphon and wield its energy to empower the blood elves into paladins. 
    
With the threat of the Voidstorm looming over Silvermoon, Astalor once again thinks of unusual methods to combat the threat: by hunting down dangerous individuals and harvesting their anguish to transform it into powerful energy. It's yet to be seen what results he will yield...]]
IMAGOdb.npcs.CAT_QUELTHALAS["astalor_bloodsworn"].zones = {"Eversong Woods", "Harandar", "Voidstorm", "Atal'Aman", "Silvermoon City"}
IMAGOdb.npcs.CAT_QUELTHALAS["astalor_bloodsworn"].source = "Cadash - IMAGO Community"
IMAGOdb.npcs.CAT_QUELTHALAS["astalor_bloodsworn"].timeline = {
    {era = "WC3", text = "Co-founded the Blood Knight paladin order by finding a way for the elves to wield the holy light again – by draining it from a captured Naaru."},
    {era = "TBC", text = "Helped defend Silvermoon against their treacherous leader Kael'thas."},
    {era = "WoD", text = "Supplied blood elven forces with golems powered by blood magic to reinforce Lady Liadrin's crusade against the Iron Horde."},
    {era = "Midnight", text = "Experimented with a new type of magic – anguish – to empower the city's defenses and ensure the survival and prosperity of the blood elves."},
}


-- CAT_LIGHT
IMAGOdb.npcs.CAT_LIGHT["mehlar_daemmerklinge"].name = "Mehlar Dawnblade"
IMAGOdb.npcs.CAT_LIGHT["mehlar_daemmerklinge"].race = "Blood Elf"
IMAGOdb.npcs.CAT_LIGHT["mehlar_daemmerklinge"].lore = "Once a hopeful paladin student of Uther the Lightbringer, Mehlar Dawnblade fell into deep bitterness after the fall of Quel'Thalas. He blamed Uther for the destruction of his homeland and in his wrath even had his old master's tomb defiled. However, through the redemption of the Blood Knights, he eventually returned to righteousness, joined the Silver Hand, and fights in Midnight as a faithful champion of the Light."
IMAGOdb.npcs.CAT_LIGHT["mehlar_daemmerklinge"].zones = {"Isle of Quel'Danas", "Parhelion Plaza"}
IMAGOdb.npcs.CAT_LIGHT["mehlar_daemmerklinge"].source = "warcraft.wiki.gg/wiki/Mehlar_Dawnblade"
IMAGOdb.npcs.CAT_LIGHT["mehlar_daemmerklinge"].timeline = {
    {era = "Pre-Classic", text = "Studied as a young elf under Uther the Lightbringer, but felt abandoned by him during the fall of Quel'Thalas."},
    {era = "Classic", text = "Sent adventurers from the Bulwark to defile the tomb of his former mentor, Uther."},
    {era = "Legion", text = "Joined the newly reformed Order of the Silver Hand in the Sanctum of Light."},
    {era = "Midnight", text = "Defends Parhelion Plaza and the Isle of Quel'Danas as a veteran Blood Knight against the Void."},
}

IMAGOdb.npcs.CAT_LIGHT["danath_trollbann"].name = "Danath Trollbane"
IMAGOdb.npcs.CAT_LIGHT["danath_trollbann"].race = "Human"
IMAGOdb.npcs.CAT_LIGHT["danath_trollbann"].lore = "The rightful ruler of the kingdom of Stromgarde and longtime hero of the Alliance. Danath Trollbane has fought and bled for humankind since the days of the Second War. A member of the Sons of Lothar, Danath built close ties with his compatriots in their time beyond the Dark Portal. Having returned to Azeroth to take up the mantle of King of Stromgarde, Danath seeks to lead his people back to their former glory."
IMAGOdb.npcs.CAT_LIGHT["danath_trollbann"].zones = {"Arcantina", "Burning Steppes", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["danath_trollbann"].source = ""
IMAGOdb.npcs.CAT_LIGHT["danath_trollbann"].timeline = {
    {era = "WC2", text = "Served under General Turalyon as a commander and tactician of the Alliance of Lordaeron, repelling the orcish Horde that threatened the Eastern Kingdoms and pursuing them beyond the Dark Portal to their homeworld of Draenor."},
    {era = "TBC", text = "Led the forces of Honor Hold in staving off the demonic armies of Hellfire Peninsula. (See rewrite below, hit character limit)"},
    {era = "Legion", text = "Aided heroic warriors in acquiring Strom’kar, the Warbreaker. This legendary sword once belonged to King Thoradin, the first human king and ancestor of Danath Trollbane himself. After the fall of the Legion, Danath returned to a long-ruined Stromgarde to rebuild the city and claim his birthright as king."},
    {era = "BfA", text = "Fought in the Battle of Stromgarde, leading his forces in the defense of their city. The struggle for the Arathi Highlands raged between the Horde and Alliance, sowing chaos across the formerly tranquil farmland."},
    {era = "TWW", text = "Joined the Alliance forces dispatched to Khaz Algar to combat the Harbinger, Xal’atath, and her nerubian forces. Routed a rebellion led by human supremacist Marran Trollbane, niece of Danath and regent of Stromgarde in his absence."},
    {era = "Midnight", text = "Helped Arator learn the history of his father, Turalyon, and his part in the events of the Second War. Introduced heroes to the Arcantina, a home away from home for adventurers from all over Azeroth."},
}

IMAGOdb.npcs.CAT_LIGHT["anduin_wrynn"].name = "Anduin Wrynn"
IMAGOdb.npcs.CAT_LIGHT["anduin_wrynn"].race = "Human"
IMAGOdb.npcs.CAT_LIGHT["anduin_wrynn"].lore = "Once the idealistic King of Stormwind and High King of the Alliance. During the events in the Shadowlands, Anduin was dominated by the Jailer and forced to commit unspeakable acts. Consumed by guilt and seemingly abandoned by the Light, he laid down his crown and wandered as a broken man through Khaz Algar (The War Within). In Midnight, the circle is completed: he rediscovers his faith in the Light and fights no longer as a king, but as a pure champion of righteousness defending Silvermoon and the Sunwell."
IMAGOdb.npcs.CAT_LIGHT["anduin_wrynn"].zones = {"Isle of Quel'Danas", "Parhelion Plaza", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["anduin_wrynn"].source = "warcraft.wiki.gg/wiki/Anduin_Wrynn"
IMAGOdb.npcs.CAT_LIGHT["anduin_wrynn"].timeline = {
    {era = "Legion", text = "Took the throne of Stormwind following the tragic death of his father, Varian."},
    {era = "BfA", text = "Led the Alliance in the Fourth War, constantly striving for peace despite Sylvanas's atrocities."},
    {era = "SL", text = "Was dominated by the Jailer Zovaal and used as a weapon against his own allies."},
    {era = "TWW", text = "Refused to return to the throne, searching Khaz Algar for inner peace and his lost faith."},
    {era = "Midnight", text = "Finally returns to the embrace of the Light to fight side by side with the elves against the Void."},
}

IMAGOdb.npcs.CAT_LIGHT["turalyon"].name = "High Exarch Turalyon"
IMAGOdb.npcs.CAT_LIGHT["turalyon"].race = "Human"
IMAGOdb.npcs.CAT_LIGHT["turalyon"].lore = "High Exarch Turalyon is a legendary figure and one of the first five paladins of the Silver Hand. After his disappearance on Draenor, he fought for millennia alongside the naaru as the leader of the Army of the Light against the Burning Legion. As a Light-infused immortal, he embodies unwavering resistance against the forces of darkness. In Midnight, he leads the defense of the sacred sites of Quel'Thalas, standing as a shining bulwark against the encroaching Void that threatens his home and his family."
IMAGOdb.npcs.CAT_LIGHT["turalyon"].zones = {"The Voidspire", "Eversong Woods", "Isle of Quel'Danas", "Voidstorm", "Parhelion Plaza", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["turalyon"].source = "warcraft.wiki.gg/wiki/Turalyon"
IMAGOdb.npcs.CAT_LIGHT["turalyon"].timeline = {
    {era = "WC2", text = "Served as Anduin Lothar's second-in-command and took leadership after his death to defeat the Horde at Blackrock Mountain."},
    {era = "WC2", text = "Led the Alliance Expedition through the Dark Portal to Draenor and stayed behind to protect Azeroth when the portal was destroyed."},
    {era = "Legion", text = "Returns as High Exarch of the Army of the Light and key leader in the final strike against the Burning Legion on Argus."},
    {era = "BfA/TWW", text = "Served as Regent of Stormwind and Lord Commander of Alliance forces during King Anduin's absence."},
    {era = "Midnight", text = "Commands the defense of the Isle of Quel'Danas and leads the Light against Xal'atath's Void invasion."},
}

IMAGOdb.npcs.CAT_LIGHT["prophet_velen"].name = "Prophet Velen"
IMAGOdb.npcs.CAT_LIGHT["prophet_velen"].race = "Draenei"
IMAGOdb.npcs.CAT_LIGHT["prophet_velen"].lore = "Prophet Velen is the spiritual leader of the draenei and one of the wisest beings in the cosmos. He led his people away from Argus 25,000 years ago to escape the corruption of the Burning Legion. Velen is inextricably linked to elven history: after the betrayal of Kael'thas, he used the spark of the fallen naaru M'uru to purify the Sunwell, restoring it as a fount of holy and arcane light. In Midnight, he returns to this sacred place to aid Quel'Thalas against the Void."
IMAGOdb.npcs.CAT_LIGHT["prophet_velen"].zones = {"Isle of Quel'Danas", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["prophet_velen"].source = "warcraft.wiki.gg/wiki/Velen"
IMAGOdb.npcs.CAT_LIGHT["prophet_velen"].timeline = {
    {era = "Pre-Classic", text = "Fled from Argus and led the draenei through the cosmos for millennia, hunted by the Legion."},
    {era = "TBC", text = "Crashed on Azeroth with the Exodar and ultimately purified the Sunwell using the heart of M'uru."},
    {era = "Legion", text = "Led the assault on Argus and finally confronted his former brother, Kil'jaeden."},
    {era = "Midnight", text = "Stands as a mentor and defender at the Sunwell to halt Xal'atath's Void invasion."},
}

IMAGOdb.npcs.CAT_LIGHT["calia_menethil"].name = "Calia Menethil"
IMAGOdb.npcs.CAT_LIGHT["calia_menethil"].race = "Light-bound Undead"
IMAGOdb.npcs.CAT_LIGHT["calia_menethil"].lore = "Princess Calia Menethil is the last heir of the Menethil dynasty and the sister of Arthas. After living in hiding under a false name for decades, she re-emerged during the Fourth War, only to be killed by Sylvanas Windrunner. Through an unprecedented miracle of the Light, she returned as a unique, light-infused undead. In Midnight, she stands at the Sunwell as a living paradox and a symbol of hope, coordinating the forces of Light against the all-consuming Void."
IMAGOdb.npcs.CAT_LIGHT["calia_menethil"].zones = {"Isle of Quel'Danas", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["calia_menethil"].source = "warcraft.wiki.gg/wiki/Calia_Menethil"
IMAGOdb.npcs.CAT_LIGHT["calia_menethil"].timeline = {
    {era = "WC3", text = "Fled during the destruction of Lordaeron by her brother Arthas and lived unrecognized among humans for years."},
    {era = "Legion", text = "Revealed herself to Alonsus Faol and joined the Conclave in the Sanctum of Light to aid priests in the battle against the Legion."},
    {era = "BfA", text = "Was killed by Sylvanas at the Arathi Highlands gathering and resurrected as light-bound undead by Saa'ra and Anduin."},
    {era = "DF", text = "Took her place on the Desolate Council to lead the Forsaken into a new era without Sylvanas."},
    {era = "Midnight", text = "Supports the defense of Quel'Thalas and serves as a diplomatic bridge between the Light and the undead."},
}

IMAGOdb.npcs.CAT_LIGHT["taelia_fordragon"].name = "Taelia Fordragon"
IMAGOdb.npcs.CAT_LIGHT["taelia_fordragon"].race = "Human"
IMAGOdb.npcs.CAT_LIGHT["taelia_fordragon"].lore = "Taelia Fordragon is the daughter of the legendary Bolvar Fordragon. Raised in Kul Tiras as a ward of Cyrus Crestfall, she spent most of her life believing her father fell at the Wrathgate. It was only during the Fourth War that she learned the shocking truth about his fate as the Lich King. Driven by an unwavering sense of justice and her father's legacy, she has developed into a capable knight. In Midnight, she fights on the front lines to defend the Light against the Void and fulfill the Fordragon name with honor."
IMAGOdb.npcs.CAT_LIGHT["taelia_fordragon"].zones = {"Eversong Woods", "Isle of Quel'Danas", "Parhelion Plaza", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["taelia_fordragon"].source = "warcraft.wiki.gg/wiki/Taelia_Fordragon"
IMAGOdb.npcs.CAT_LIGHT["taelia_fordragon"].timeline = {
    {era = "Pre-Classic", text = "Was sent to Kul Tiras by her father to protect her from the dangers of Lordaeron and the Third War."},
    {era = "BfA", text = "Served as a messenger in Kul Tiras, met Jaina Proudmoore, and eventually learned of Bolvar's fate in Icecrown Citadel."},
    {era = "SL", text = "Traveled to the Shadowlands to fight alongside her father and the Knights of the Ebon Blade against the Jailer."},
    {era = "Midnight", text = "Supports the defense of Silvermoon and Quel'Danas as a prominent knight of the Army of Light."},
}

IMAGOdb.npcs.CAT_LIGHT["moira_thaurissan"].name = "Moira Thaurissan"
IMAGOdb.npcs.CAT_LIGHT["moira_thaurissan"].race = "Dwarf (Dark Iron)"
IMAGOdb.npcs.CAT_LIGHT["moira_thaurissan"].lore = "Moira Thaurissan is the heir to the throne of Ironforge and regent of the Dark Iron clan. As a member of the Council of Three Hammers, she has united the once-feuding dwarven clans through iron will and political savvy. Moira is not only a capable diplomat but also a powerful priestess. In Midnight, she represents the dwarves at the Sunwell, bringing the combined might of Dark Iron magic and the Light to save Quel'Thalas from total darkness."
IMAGOdb.npcs.CAT_LIGHT["moira_thaurissan"].zones = {"Isle of Quel'Danas", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["moira_thaurissan"].source = "warcraft.wiki.gg/wiki/Moira_Thaurissan"
IMAGOdb.npcs.CAT_LIGHT["moira_thaurissan"].timeline = {
    {era = "Classic", text = "Disappeared from Ironforge and became the consort of Emperor Dagran Thaurissan in Blackrock Depths."},
    {era = "Cata", text = "Returned to Ironforge after her father Magni's petrification and helped found the Council of Three Hammers."},
    {era = "BfA", text = "Secured the official integration of the Dark Iron dwarves into the Alliance during the Fourth War."},
    {era = "TWW", text = "Accompanied the expedition to Khaz Algar and supported her son Dagran II in his first diplomatic steps."},
    {era = "Midnight", text = "Fights as a leading priestess and representative of the dwarves in the defense of the Sunwell."},
}

IMAGOdb.npcs.CAT_LIGHT["hauptmann_fareeya"].name = "Captain Fareeya"
IMAGOdb.npcs.CAT_LIGHT["hauptmann_fareeya"].race = "Lightforged Draenei"
IMAGOdb.npcs.CAT_LIGHT["hauptmann_fareeya"].lore = "Captain Fareeya is the high field commander of the Lightforged Draenei and one of High Exarch Turalyon's most trusted officers. During the thousand-year war against the Burning Legion, she led countless operations aboard the Vindicaar. Fareeya is known for her unwavering discipline and her indomitable faith in the Holy Light. In Midnight, she leads the Lightforged contingent on the Isle of Quel'Danas, fortifying the Sunwell against the Void with advanced technology and divine power."
IMAGOdb.npcs.CAT_LIGHT["hauptmann_fareeya"].zones = {"Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_LIGHT["hauptmann_fareeya"].source = "warcraft.wiki.gg/wiki/Captain_Fareeya"
IMAGOdb.npcs.CAT_LIGHT["hauptmann_fareeya"].timeline = {
    {era = "Legion", text = "Served as a central commander of the Army of the Light during the Argus campaign, assisting the heroes of Azeroth."},
    {era = "BfA", text = "Officially led the Lightforged Draenei into the Alliance and oversaw the training of new recruits on the Vindicaar."},
    {era = "Midnight", text = "Commands the defensive positions on the Isle of Quel'Danas and coordinates Light artillery against the Void portals."},
}

IMAGOdb.npcs.CAT_LIGHT["delas_mondfang"].name = "Delas Moonfang"
IMAGOdb.npcs.CAT_LIGHT["delas_mondfang"].race = "Night Elf"
IMAGOdb.npcs.CAT_LIGHT["delas_mondfang"].lore = "Delas Moonfang is a historical pioneer: a former Priestess of Elune, she was the first Night Elf to walk the path of the Paladin and join the Order of the Silver Hand. Under the tutelage of Mehlar Dawnblade, she learned to harmonize the Holy Light with the traditions of her people. In Midnight, she serves as a living symbol of unity at the Sunwell, proving that faith in the Light knows no boundaries between elven peoples when it comes to defending Azeroth."
IMAGOdb.npcs.CAT_LIGHT["delas_mondfang"].zones = {"Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_LIGHT["delas_mondfang"].source = "warcraft.wiki.gg/wiki/Delas_Moonfang"
IMAGOdb.npcs.CAT_LIGHT["delas_mondfang"].timeline = {
    {era = "WoD", text = "Served as a Priestess of the Moon in Shadowmoon Valley on Draenor, assisting Alliance forces against the Iron Horde."},
    {era = "Legion", text = "Joined the Silver Hand and was ordained as the first Night Elf Paladin in the Sanctum of Light."},
    {era = "Midnight", text = "Fights as an experienced Paladin on the Isle of Quel'Danas for the defense of the Sunwell."},
}

IMAGOdb.npcs.CAT_LIGHT["lord_grayson_schattenbruch"].name = "Lord Grayson Shadowbreaker"
IMAGOdb.npcs.CAT_LIGHT["lord_grayson_schattenbruch"].race = "Human"
IMAGOdb.npcs.CAT_LIGHT["lord_grayson_schattenbruch"].lore = "Lord Grayson Shadowbreaker is a highly respected Paladin Master of the Silver Hand. For years, he served in the Cathedral of Light in Stormwind as a mentor and was instrumental in the training and outfitting of the knightly cavalry. During the invasion of the Burning Legion, he joined the reformed order in the Sanctum of Light. In Midnight, he brings his decades of experience to the fronts of Quel'Thalas to support the defense of the Sunwell with the holy wrath of the Silver Hand."
IMAGOdb.npcs.CAT_LIGHT["lord_grayson_schattenbruch"].zones = {"Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_LIGHT["lord_grayson_schattenbruch"].source = "warcraft.wiki.gg/wiki/Lord_Grayson_Shadowbreaker"
IMAGOdb.npcs.CAT_LIGHT["lord_grayson_schattenbruch"].timeline = {
    {era = "Classic", text = "Instructed young paladins in Stormwind and helped them summon their holy steeds."},
    {era = "Legion", text = "Joined the Conclave in the Sanctum of Light to unite the Order of the Silver Hand against Sargeras' Legion."},
    {era = "Midnight", text = "Commands Silver Hand troops on the Isle of Quel'Danas in defense of the Light."},
}

IMAGOdb.npcs.CAT_LIGHT["eadric_der_reine"].name = "Eadric the Pure"
IMAGOdb.npcs.CAT_LIGHT["eadric_der_reine"].race = "Human"
IMAGOdb.npcs.CAT_LIGHT["eadric_der_reine"].lore = "Eadric the Pure is the Grand Champion of the Argent Crusade and one of the most virtuous paladins in the order's history. Known for his humility and unwavering faith, he served as the final test at the Grand Tournament in Northrend for those wishing to prove themselves against the Lich King. Despite his high rank, he has always maintained a spark of humor and deep humanity. In Midnight, he leads the defense of Parhelion Plaza, proving that true purity is the brightest bulwark against the shadows of the Void."
IMAGOdb.npcs.CAT_LIGHT["eadric_der_reine"].zones = {"Parhelion Plaza"}
IMAGOdb.npcs.CAT_LIGHT["eadric_der_reine"].source = "warcraft.wiki.gg/wiki/Eadric_the_Pure"
IMAGOdb.npcs.CAT_LIGHT["eadric_der_reine"].timeline = {
    {era = "WotLK", text = "Served as Grand Champion of the Argent Crusade and tested the heroes of Azeroth in the Trial of the Crusader."},
    {era = "Legion", text = "Joined the Conclave in the Sanctum of Light and supported the Highlord in leading the Order of the Silver Hand."},
    {era = "Midnight", text = "Defends Parhelion Plaza against the Void invasion and serves as a moral anchor for the forces of Light."},
}

IMAGOdb.npcs.CAT_LIGHT["yalia_weisenwisper"].name = "Yalia Sagewhisper"
IMAGOdb.npcs.CAT_LIGHT["yalia_weisenwisper"].race = "Pandaren"
IMAGOdb.npcs.CAT_LIGHT["yalia_weisenwisper"].lore = "Yalia Sagewhisper is a high-ranking priestess of the Shado-Pan from Pandaria. She is renowned for her unwavering calm and her ability to bring spiritual peace even in the darkest moments. During the invasion of the Burning Legion, she joined the Conclave in the Sanctum of Light to unite the priests of Azeroth. In Midnight, she brings the meditative practices and healing arts of her people to Parhelion Plaza, serving as a moral anchor and healer for the united defenders of Quel'Thalas."
IMAGOdb.npcs.CAT_LIGHT["yalia_weisenwisper"].zones = {"Parhelion Plaza"}
IMAGOdb.npcs.CAT_LIGHT["yalia_weisenwisper"].source = "warcraft.wiki.gg/wiki/Yalia_Sagewhisper"
IMAGOdb.npcs.CAT_LIGHT["yalia_weisenwisper"].timeline = {
    {era = "MoP", text = "Served the Shado-Pan on the Isle of Thunder and supported heroes in the fight against the Thunder King Lei Shen."},
    {era = "Legion", text = "Became a founding member of the Conclave in the Sanctum of Light to combat the Legion's shadows with inner strength."},
    {era = "Midnight", text = "Provides spiritual support and healing at Parhelion Plaza during the Void siege."},
}

IMAGOdb.npcs.CAT_LIGHT["lothraxion"].name = "Lothraxion"
IMAGOdb.npcs.CAT_LIGHT["lothraxion"].race = "Lightforged Dreadlord"
IMAGOdb.npcs.CAT_LIGHT["lothraxion"].lore = "Lothraxion is an absolute rarity in the cosmos: he is a nathrezim (dreadlord) forged with the Holy Light by the prime naaru Xe'ra. As a high-ranking commander of the Army of the Light, his loyalty to the Light appears unwavering, even though his true origins from the Shadowlands often arouse deep suspicion among some. In Midnight, he coordinates the Light's massive military offensive and can be found on the front lines of nearly every crisis zone in Quel'Thalas and the Voidstorm."
IMAGOdb.npcs.CAT_LIGHT["lothraxion"].zones = {"Isle of Quel'Danas", "Voidstorm", "Nexus Point Xenas", "Parhelion Plaza", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["lothraxion"].source = "warcraft.wiki.gg/wiki/Lothraxion"
IMAGOdb.npcs.CAT_LIGHT["lothraxion"].timeline = {
    {era = "Legion", text = "Revealed himself as a Lightforged demon and assisted the paladins in the Sanctum of Light in the battle against Balnazzar."},
    {era = "SL", text = "A report in Revendreth (Enemy Infiltration) raised the dark suspicion that he might be a sleeper agent of Sire Denathrius."},
    {era = "Midnight", text = "Emerges as the supreme military strategist of the Light in countless zones of Quel'Thalas."},
}

IMAGOdb.npcs.CAT_LIGHT["alonsus_faol"].name = "Archbishop Alonsus Faol"
IMAGOdb.npcs.CAT_LIGHT["alonsus_faol"].race = "Forsaken"
IMAGOdb.npcs.CAT_LIGHT["alonsus_faol"].lore = "Archbishop Alonsus Faol is one of the most historically significant figures in Azeroth. After the fall of Stormwind in the First War, he realized that pure priests were too vulnerable on the battlefield. Together with Uther, he founded the Order of the Silver Hand, creating the first paladins. Faol died before the Third War but was raised by the Scourge as an undead. Through unimaginable willpower, he broke free and continues to wield the Holy Light, even though it causes him physical pain as a Forsaken. In Midnight, the living legend travels to historic Alliance sites and Quel'Thalas to bless the defenders in the war against the Void."
IMAGOdb.npcs.CAT_LIGHT["alonsus_faol"].zones = {"Burning Steppes", "Arathi Highlands", "Isle of Quel'Danas", "Eastern Plaguelands", "Parhelion Plaza", "Silvermoon City", "Tirisfal Glades"}
IMAGOdb.npcs.CAT_LIGHT["alonsus_faol"].source = "warcraft.wiki.gg/wiki/Alonsus_Faol"
IMAGOdb.npcs.CAT_LIGHT["alonsus_faol"].timeline = {
    {era = "WC2", text = "Founded the Order of the Silver Hand and ordained the first five paladins (including Uther and Turalyon)."},
    {era = "Pre-WC3", text = "Died of natural causes and was buried in Faol's Rest in Tirisfal before being raised by the Scourge."},
    {era = "Legion", text = "Stepped out of the shadows to found the Conclave in the Netherlight Temple and lead priests against the Legion."},
    {era = "Midnight", text = "Undertakes a far-reaching pilgrimage across Azeroth to Quel'Thalas to rally the spiritual forces of the Light."},
}

IMAGOdb.npcs.CAT_LIGHT["tahu_weisenwind"].name = "Tahu Sagewind"
IMAGOdb.npcs.CAT_LIGHT["tahu_weisenwind"].race = "Tauren"
IMAGOdb.npcs.CAT_LIGHT["tahu_weisenwind"].lore = "Tahu Sagewind is the spiritual founder of the Seers, the tauren priesthood. While humans revere the Holy Light, Tahu taught his people to channel the Light through An'she—the sun and the right eye of the Earth Mother. His presence in Quel'Thalas during Midnight holds immense diplomatic and poetic significance: the Horde's master of sun magic stands alongside the blood elves to protect their own Sunwell from the all-consuming hunger of the Void."
IMAGOdb.npcs.CAT_LIGHT["tahu_weisenwind"].zones = {"Isle of Quel'Danas", "Parhelion Plaza", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["tahu_weisenwind"].source = "warcraft.wiki.gg/wiki/Tahu_Sagewind"
IMAGOdb.npcs.CAT_LIGHT["tahu_weisenwind"].timeline = {
    {era = "WotLK", text = "Discussed the imbalance between Mu'sha (Moon) and An'she (Sun) with Aponi Brightmane, laying the foundation for tauren paladins and priests."},
    {era = "Cata", text = "Officially founded the order of the Seers, teaching the tauren to wield the power of An'she."},
    {era = "Legion", text = "Represented the tauren in the Conclave at the Netherlight Temple, fighting alongside the priests of Azeroth."},
    {era = "Midnight", text = "Travels to Silvermoon and Quel'Danas to bring the light of An'she into the elves' darkest battle."},
}

IMAGOdb.npcs.CAT_LIGHT["aponi_lichtmaehne"].name = "Aponi Brightmane"
IMAGOdb.npcs.CAT_LIGHT["aponi_lichtmaehne"].race = "Tauren"
IMAGOdb.npcs.CAT_LIGHT["aponi_lichtmaehne"].lore = "Aponi Brightmane is the High Chieftain of the Sunwalkers, the order of tauren paladins. As a former warrior, she was severely wounded in the war against the Scourge. In long conversations with Tahu Sagewind, she realized her people had lost sight of the Earth Mother's balance. By turning to the power of An'she (the sun), she became the very first Sunwalker. In Midnight, she stands shoulder to shoulder with the paladins of the Silver Hand at Parhelion Plaza, unleashing the light of An'she against absolute darkness."
IMAGOdb.npcs.CAT_LIGHT["aponi_lichtmaehne"].zones = {"Isle of Quel'Danas", "Parhelion Plaza"}
IMAGOdb.npcs.CAT_LIGHT["aponi_lichtmaehne"].source = "warcraft.wiki.gg/wiki/Aponi_Brightmane"
IMAGOdb.npcs.CAT_LIGHT["aponi_lichtmaehne"].timeline = {
    {era = "WotLK", text = "Was wounded as a warrior in Northrend and laid the ideological foundation for sun magic with Tahu."},
    {era = "Cata", text = "Officially founded the Sunwalkers and became the first tauren paladin."},
    {era = "Legion", text = "Joined the reformed Silver Hand in the Sanctum of Light as a high-ranking champion."},
    {era = "Midnight", text = "Defends Quel'Danas and Parhelion Plaza with the concentrated radiant power of the sun."},
}

IMAGOdb.npcs.CAT_LIGHT["kriegskaplanin_senn"].name = "War Chaplain Senn"
IMAGOdb.npcs.CAT_LIGHT["kriegskaplanin_senn"].race = "Lightforged Draenei"
IMAGOdb.npcs.CAT_LIGHT["kriegskaplanin_senn"].lore = "War Chaplain Senn is a Lightforged draenei and one of High Exarch Turalyon's most loyal lieutenants. After the Fourth War, she aided him in the relentless hunt for Sylvanas Windrunner in the Arathi Highlands. There, she reluctantly had to cooperate with the void elf Celosel Nightgiver—an experience that triggered physical disgust for Void magic in the Lightforged veteran. In Midnight, she joins the Vanguard of Light. With holy wrath and a deep abhorrence for the shadows, she confronts the invaders at the Sunwell and in the Voidstorm."
IMAGOdb.npcs.CAT_LIGHT["kriegskaplanin_senn"].zones = {"The Void Spire", "Isle of Quel'Danas", "Voidstorm", "Parhelion Plaza", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["kriegskaplanin_senn"].source = "warcraft.wiki.gg/wiki/War_Chaplain_Senn"
IMAGOdb.npcs.CAT_LIGHT["kriegskaplanin_senn"].timeline = {
    {era = "BfA", text = "Hunted Sylvanas with Turalyon in the Arathi Highlands and openly showed her deep disgust for the Void magic of the ren'dorei."},
    {era = "Midnight", text = "Serves in the Vanguard of Light, fighting absolute darkness in the most dangerous zones of Quel'Thalas."},
}

IMAGOdb.npcs.CAT_LIGHT["faerin_lothar"].name = "Faerin Lothar"
IMAGOdb.npcs.CAT_LIGHT["faerin_lothar"].race = "Human (Arathi)"
IMAGOdb.npcs.CAT_LIGHT["faerin_lothar"].lore = "Faerin Lothar is one of the most charismatic leaders of the Arathi Expedition in Khaz Algar and the direct descendant of the legendary bloodline of Anduin Lothar. As a child, she barely survived the destruction of the Arathi armada by a leviathan in the deep waters, losing an arm and an eye in the process. Rather than breaking, she wields a massive shield prosthetic and fights with unwavering faith in the Sacred Flame. In The War Within, she became the most crucial moral support for Anduin Wrynn. In Midnight, the Lothar legacy returns to the surface: Faerin brings the fiery determination of the Arathi Empire to Quel'Thalas to defend the Light against absolute darkness."
IMAGOdb.npcs.CAT_LIGHT["faerin_lothar"].zones = {"Isle of Quel'Danas", "Parhelion Plaza", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["faerin_lothar"].source = "warcraft.wiki.gg/wiki/Faerin_Lothar"
IMAGOdb.npcs.CAT_LIGHT["faerin_lothar"].timeline = {
    {era = "TWW", text = "Discovered in Hallowfall. Leads the resistance against the nerubians of Azj-Kahet and helps Anduin Wrynn overcome his severe trauma and lost connection to the Light."},
    {era = "Midnight", text = "Travels from the depths of Khaz Algar to the surface to support the defense of Quel'Thalas, Silvermoon, and Parhelion Plaza as a champion of the Light."},
}

IMAGOdb.npcs.CAT_LIGHT["generalin_bellamy"].name = "General Amias Bellamy"
IMAGOdb.npcs.CAT_LIGHT["generalin_bellamy"].race = "Human (Arathi)"
IMAGOdb.npcs.CAT_LIGHT["generalin_bellamy"].lore = "General Amias Bellamy is the highest-ranking military commander of the Arathi Expedition. A pragmatic and battle-hardened tactician, she led the endless war against the nerubians and creatures of the deep in Hallowfall, always guided by her faith in the Sacred Flame. Unlike Faerin Lothar, who often represents the heart of the Arathi, Bellamy is the iron shield and drawn sword of her people. In Midnight, she has moved her troops from the underground to the surface. Under her command, the Arathi army does not limit itself to pure defense but launches offensive counterstrikes deep into the Voidstorm and the Void Spire."
IMAGOdb.npcs.CAT_LIGHT["generalin_bellamy"].zones = {"The Voidspire", "Isle of Quel'Danas", "Voidstorm", "Silvermoon City"}
IMAGOdb.npcs.CAT_LIGHT["generalin_bellamy"].source = "warcraft.wiki.gg/wiki/General_Amias_Bellamy"
IMAGOdb.npcs.CAT_LIGHT["generalin_bellamy"].timeline = {
    {era = "TWW", text = "Commands the Arathi Expedition in Hallowfall, holding the line against the relentless attacks from Azj-Kahet."},
    {era = "Midnight", text = "Leads the Arathi military offensive on the surface, commanding troops from Silvermoon to the center of the Voidstorm."},
}

IMAGOdb.npcs.CAT_LIGHT["arator"].name = "Arator the Redeemer"
IMAGOdb.npcs.CAT_LIGHT["arator"].race = "Half-Elf"
IMAGOdb.npcs.CAT_LIGHT["arator"].lore =
[[
When his parents Alleria Windrunner and Turalyon left for Draenor to save Azeroth, they left their newborn behind. Raised by family, Arator only knew his parents through legend. As the child of two of the Alliance's most famous war heroes, Arator has always struggled to step out of their shadows and find his own destiny. 
    
Choosing to emulate his father, he became a paladin for the Alliance and rose up in the ranks by showing true strength and faith in the Light. Now reunited with his parents, Arator struggles to hold his family together as they are pulled in different directions.]]
IMAGOdb.npcs.CAT_LIGHT["arator"].zones = {"Amirdrassil", "Arcantina", "Burning Steppes", "Arathi Highlands", "The Void Spire", "Harandar", "Den of Masters", "Eversong Woods", "Isle of Quel'Danas", "Voidstorm", "Eastern Plaguelands", "Parhelion Plaza", "Silvermoon City", "Zul'Aman"}
IMAGOdb.npcs.CAT_LIGHT["arator"].source = "Cadash"
IMAGOdb.npcs.CAT_LIGHT["arator"].timeline = {
    {era = "WC2", text = "Born during the Second War and left behind on Azeroth to be raised by his aunt, Vereesa Windrunner."},
    {era = "WC3", text = "After surviving the Third War, Vereesa brought him to Silvermoon where he was trained by Lor'themar and Liadrin in the ways of the Light."},
    {era = "TBC", text = [[Joined the expedition to Outland to look for his parents. Served under the banner Alliance as a paladin. He was dubbed "Arator the Redeemer".]]},
    {era = "Legion", text = "Joined the Order of the Silver Hand and defended the Netherlight Temple. Fought the Burning Legion on Argus and was finally reunited with his parents."},
    {era = "TWW", text = "Tried to rally Alleria and Sylvanas Windrunner to the imminent defense of Silvermoon."},
    {era = "Midnight", text = "After being summoned by the Sunwell, Arator fought on the front lines against the Void. He organized the reunification of the elven nations of Azeroth to fight a common foe."},
}

IMAGOdb.npcs.CAT_LIGHT["nolaki"].name = "Nolaki"
IMAGOdb.npcs.CAT_LIGHT["nolaki"].race = "Zandalari Troll"
IMAGOdb.npcs.CAT_LIGHT["nolaki"].lore = "Nolaki is a Zandalari Prelate and the current 'Exemplar of Sacrifice' in the newly reformed Tyr's Guard. Her resolve was forged during the Battle of Dazar'alor: at the time, she stayed behind, feeling she was too inexperienced, while her mentor Ra'wani Kanae fell in battle against the Alliance. Plagued by guilt, Nolaki swore to use the Light until her dying breath to save lives. This led her to the Dragon Isles, where she was recruited by Travard into Tyr's Guard. In Midnight, she faces her ultimate test: traveling to the Isle of Quel'Danas to stand on the front lines and make every possible sacrifice to prevent the Sunwell from falling to the Void."
IMAGOdb.npcs.CAT_LIGHT["nolaki"].zones = {"Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_LIGHT["nolaki"].source = "warcraft.wiki.gg/wiki/Nolaki"
IMAGOdb.npcs.CAT_LIGHT["nolaki"].timeline = {
    {era = "BfA", text = "Stayed behind during the Battle of Dazar'alor and lost her beloved mentor Ra'wani Kanae, which shaped her unwavering path as a paladin."},
    {era = "DF", text = "Traveled to the Dragon Isles, joined Tyr's Guard, and proudly accepted the title of Exemplar of Sacrifice."},
    {era = "Midnight", text = "Fights as external support of the Light orders on the Isle of Quel'Danas against the advancing Void invasion."},
}

IMAGOdb.npcs.CAT_LIGHT["valunei"].name = "Valunei"
IMAGOdb.npcs.CAT_LIGHT["valunei"].race = "Lightforged Draenei"
IMAGOdb.npcs.CAT_LIGHT["valunei"].lore = "Valunei is a Lightforged draenei and the current 'Exemplar of Compassion' in the newly reformed Tyr's Guard. On Argus, she learned the ways of the Light from her mentor Vindicator Iriska and spent countless years fighting the horrors of the Burning Legion. She deeply despises unnecessary suffering and has made it her life's mission to heal and protect the innocent. After arriving on Azeroth, she was recruited by Travard into Tyr's Guard on the Dragon Isles. In Midnight, her unwavering path of compassion leads her to the Isle of Quel'Danas. There, she uses her remarkable healing powers on the front lines to preserve the lives of the defenders and protect the Sunwell from the Void."
IMAGOdb.npcs.CAT_LIGHT["valunei"].zones = {"Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_LIGHT["valunei"].source = "warcraft.wiki.gg/wiki/Valunei"
IMAGOdb.npcs.CAT_LIGHT["valunei"].timeline = {
    {era = "Legion", text = "Fought as part of the Army of the Light on Argus against the Burning Legion and learned the teachings of the paladins."},
    {era = "DF", text = "Was inducted into Tyr's Guard on the Dragon Isles and accepted the title 'Exemplar of Compassion'."},
    {era = "Midnight", text = "Travels to the Isle of Quel'Danas to use her healing arts in the bitter war against the Void invasion."},
}

IMAGOdb.npcs.CAT_LIGHT["mariella_ward"].name = "Mariella Ward"
IMAGOdb.npcs.CAT_LIGHT["mariella_ward"].race = "Human"
IMAGOdb.npcs.CAT_LIGHT["mariella_ward"].lore = "Mariella Ward is a former priestess of the fanatical Scarlet Onslaught. When she began to question the twisted and hateful teachings of her order, she was declared a heretic and sentenced to execution in Dragonblight. Rescued at the last moment by the leader of the priesthood, she pledged her unwavering loyalty to the Conclave at the Netherlight Temple. Mariella knows the difference between blind fanaticism and true devotion to the Light like few others. In Midnight, she travels to Quel'Thalas as a representative of the Conclave to protect the Sunwell from ultimate darkness alongside other Light wielders."
IMAGOdb.npcs.CAT_LIGHT["mariella_ward"].zones = {"Isle of Quel'Danas", "Parhelion Plaza"}
IMAGOdb.npcs.CAT_LIGHT["mariella_ward"].source = "Quest: Champion: Mariella Ward"
IMAGOdb.npcs.CAT_LIGHT["mariella_ward"].timeline = {
    {era = "Legion", text = "Was rescued from execution by the Scarlet Onslaught and joined the Conclave of Priests as a champion."},
    {era = "Midnight", text = "Travels to Parhelion Plaza and the Isle of Quel'Danas to defend the Sunwell alongside other Light wielders."},
}

IMAGOdb.npcs.CAT_LIGHT["hadwin"].name = "Hadwin"
IMAGOdb.npcs.CAT_LIGHT["hadwin"].race = "Human (Kul Tiran)"
IMAGOdb.npcs.CAT_LIGHT["hadwin"].lore = "Hadwin is a burly Kul Tiran and the current 'Exemplar of Justice' in the newly reformed Tyr's Guard. Originally a worshiper of the Tidemother, he joined the Order of Embers in Drustvar as an Inquisitor to assist Lady Waycrest in fighting the coven witches. To his own surprise, he developed an inexplicable yet profound connection to the Holy Light in the process. He trained as a paladin with the Silver Hand but soon left to follow his own pragmatic code. On the Dragon Isles, he finally found his true calling within Tyr's Guard. In Midnight, Hadwin stands on the front lines at Parhelion Plaza with his massive shield, ensuring that the merciless hunger of the Void is met with iron justice."
IMAGOdb.npcs.CAT_LIGHT["hadwin"].zones = {"Isle of Quel'Danas", "Parhelion Plaza"}
IMAGOdb.npcs.CAT_LIGHT["hadwin"].source = "Quest: Ein Vorbild der Gerechtigkeit: Hadwin"
IMAGOdb.npcs.CAT_LIGHT["hadwin"].timeline = {
    {era = "BfA", text = "Fought as an Inquisitor for the Order of Embers in Drustvar against witches, discovering the Light and later becoming a paladin of the Silver Hand."},
    {era = "DF", text = "Traveled to the Dragon Isles to right wrongs and was inducted into Tyr's Guard by Travard as the Exemplar of Justice."},
    {era = "Midnight", text = "Fights as the vanguard of Tyr's Guard at Parhelion Plaza and Quel'Danas against the forces of the Void."},
}

IMAGOdb.npcs.CAT_LIGHT["talthis"].name = "Talthis"
IMAGOdb.npcs.CAT_LIGHT["talthis"].race = "Blood Elf"
IMAGOdb.npcs.CAT_LIGHT["talthis"].lore = "Talthis is a blood elf paladin and the current 'Exemplar of Order' in the newly reformed Tyr's Guard. As a child, he was forced to watch his homeland of Silvermoon fall to the absolute chaos of the Scourge invasion. This traumatic experience, along with surviving countless global catastrophes, forged within him an unwavering desire for structure, security, and order. When Travard discovered him during a Primalist assault on the Dragon Isles, Talthis did not hesitate to join Tyr's Guard. In Midnight, the son of Quel'Thalas returns to his homeland—not within the ranks of the Blood Knights, but as part of the Light's elite strike force to halt the ultimate chaos of the Void on the Isle of Quel'Danas."
IMAGOdb.npcs.CAT_LIGHT["talthis"].zones = {"Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_LIGHT["talthis"].source = "Quest: Ein Vorbild der Ordnung: Talthis"
IMAGOdb.npcs.CAT_LIGHT["talthis"].timeline = {
    {era = "WC3", text = "Witnessed the devastating fall of Silvermoon to the Scourge as a child, which shaped his lifelong pursuit of order."},
    {era = "DF", text = "Fought against the Primalists during the Flashfrost Assault on the Dragon Isles and was recruited by Travard as the Exemplar of Order."},
    {era = "Midnight", text = "Returns to his homeland to stop the chaos of the Void invasion on the Isle of Quel'Danas as part of Tyr's Guard."},
}

IMAGOdb.npcs.CAT_LIGHT["vindicator_boros"].name = "Vindicator Boros"
IMAGOdb.npcs.CAT_LIGHT["vindicator_boros"].race = "Draenei"
IMAGOdb.npcs.CAT_LIGHT["vindicator_boros"].lore = "Vindicator Boros is an unyielding veteran of the Hand of Argus and a high-ranking champion of the Silver Hand. Following the crash of the Exodar on Azeroth, he led the draenei's bitter fight against blood elf sabotage on Bloodmyst Isle. This previously deep-seated enmity makes his presence in Midnight all the more remarkable: faced with total annihilation by the Void, Boros lays old grudges to rest. Wielding his gigantic hammer and the pure power of the Light, he now stands shoulder-to-shoulder on Parhelion Plaza with the very elves he once fought, determined to protect the Sunwell."
IMAGOdb.npcs.CAT_LIGHT["vindicator_boros"].zones = {"Isle of Quel'Danas", "Parhelion Plaza"}
IMAGOdb.npcs.CAT_LIGHT["vindicator_boros"].source = "Quest: Die Hand von Argus"
IMAGOdb.npcs.CAT_LIGHT["vindicator_boros"].timeline = {
    {era = "TBC", text = "Led the forces of the Hand of Argus on Bloodmyst Isle in the battle against Kael'thas's Sunhawks."},
    {era = "Legion", text = "Joined the newly reformed Silver Hand and served the Highlord as a loyal champion in the war against the Legion."},
    {era = "Midnight", text = "Fights as the vanguard of the Silver Hand at Parhelion Plaza and the Isle of Quel'Danas against the Void invasion."},
}

IMAGOdb.npcs.CAT_LIGHT["sunwalker_dezco"].name = "Sunwalker Dezco"
IMAGOdb.npcs.CAT_LIGHT["sunwalker_dezco"].race = "Tauren"
IMAGOdb.npcs.CAT_LIGHT["sunwalker_dezco"].lore =
[[
Chieftain of the Dawnchaser tribe, Sunwalker Dezco is a steadfast tauren who reveres An'she, the sun, drawing his formidable power from her light. Having endured unimaginable personal tragedies that would break a lesser spirit, Dezco journeyed to distant lands in search of purpose. Though his travels have taken him across distant continents and even into the realms of the afterlife, the place he felt most at home was with the common people of Azeroth. 
    
Dedicated to service, Dezco stands as a seasoned veteran and wise elder among the Sunwalkers. As conflict brews anew, he serves as a guiding mentor, teaching allies that walking the path of the Light requires not only fervent zeal, but deep compassion as well.]]
IMAGOdb.npcs.CAT_LIGHT["sunwalker_dezco"].zones = {"Arathi Highlands"}
IMAGOdb.npcs.CAT_LIGHT["sunwalker_dezco"].source = "Lewi - IMAGO Community"
IMAGOdb.npcs.CAT_LIGHT["sunwalker_dezco"].timeline = {
    {era = "Pre-MoP", text = "Fought against dragons, the undead, and Alliance forces on several Horde missions across multiple continents alongside his closest allies."},
    {era = "MoP", text = "Led the Dawnchaser tribe to Pandaria, enduring the tragic deaths of his wife and one of his infant sons. He became a staunch defender of the Vale of Eternal Blossoms and ultimately helped overthrow Garrosh Hellscream to stop his desecration of the sacred land."},
    {era = "WoD", text = "Traveled to Draenor in search of peace, temporarily struggling with an addiction to the soothing, warm light of an arakkoan Sun Crystal to cope with his immense grief."},
    {era = "Legion", text = "Joined the ranks of the Silver Hand, aiding the paladin order's defensive efforts from within the Sanctum of Light."},
    {era = "BfA", text = "Departed from the Silver Hand following the fractured loyalties and political turmoil of the Fourth War."},
    {era = "SL", text = "Crossed the veil into the Shadowlands and arrived in Oribos, hoping to find the souls of his departed wife and son to deliver a final message of love."},
    {era = "TWW", text = "Traveled to the shores of Khaz Algar alongside other prominent tauren, proudly overseeing the martial training of his now-grown son, Kor."},
    {era = "Midnight", text = "Acts as a guiding mentor for the Sunwalkers and their allies, teaching a new generation that wielding the Light is about much more than mere violence."},
}


-- CAT_NEUTRAL
IMAGOdb.npcs.CAT_NEUTRAL["allari_die_seelenfresserin"].name = "Allari the Souleater"
IMAGOdb.npcs.CAT_NEUTRAL["allari_die_seelenfresserin"].race = "Blood Elf"
IMAGOdb.npcs.CAT_NEUTRAL["allari_die_seelenfresserin"].lore = "As a ruthless Demon Hunter of the Illidari, Allari is a master of enemy interrogations. Armed with the Scythe of Souls, she uses her fel-infused powers to lay bare the minds of her enemies and harvest their essences. In Midnight, she expands her merciless hunting methods to a cosmic scale, pursuing the forces of the Void into the Telogrus Rift and onto the shattered world of K'aresh."
IMAGOdb.npcs.CAT_NEUTRAL["allari_die_seelenfresserin"].zones = {"Telogrus Rift", "Eredath", "K'aresh", "Voidstorm"}
IMAGOdb.npcs.CAT_NEUTRAL["allari_die_seelenfresserin"].source = "warcraft.wiki.gg/wiki/Allari_the_Souleater"
IMAGOdb.npcs.CAT_NEUTRAL["allari_die_seelenfresserin"].timeline = {
    {era = "TBC", text = "Traveled to the Black Temple in Outland and pledged her loyalty to Illidan Stormrage."},
    {era = "Legion", text = "Fought on Mardum and the Broken Shore, using her scythe to interrogate demons in the Fel Hammer."},
    {era = "BfA", text = "Participated in the Fourth War, securing positions in the Arathi Highlands and Darkshore."},
    {era = "Midnight", text = "Leads independent, cross-faction incursions into cosmic Void zones like K'aresh and Eredath."},
}

IMAGOdb.npcs.CAT_NEUTRAL["decimus"].name = "Decimus"
IMAGOdb.npcs.CAT_NEUTRAL["decimus"].race = "Domanaar"
IMAGOdb.npcs.CAT_NEUTRAL["decimus"].lore = "Decimus is a sarcastic and pragmatic Domanaar who was once among the most powerful Void-aligned leaders in the Voidstorm. Rather than blindly submitting to Xal'atath, he operates out of pure self-interest and allies with the heroes of Azeroth. With his biting irony and invaluable knowledge of cosmic forces, he guides the construction of the Voidforge — the central progression system of the expansion — becoming the most crucial independent contact in Midnight."
IMAGOdb.npcs.CAT_NEUTRAL["decimus"].zones = {"Voidstorm"}
IMAGOdb.npcs.CAT_NEUTRAL["decimus"].source = "warcraft.wiki.gg/wiki/Decimus"
IMAGOdb.npcs.CAT_NEUTRAL["decimus"].timeline = {
    {era = "Midnight", text = "Emerges in the Voidstorm as a surprising, independent ally who guides the construction of the Voidforge."},
}

IMAGOdb.npcs.CAT_NEUTRAL["king_mrgl-mrgl"].name = "King Mrgl-Mrgl"
IMAGOdb.npcs.CAT_NEUTRAL["king_mrgl-mrgl"].race = "Murloc"
IMAGOdb.npcs.CAT_NEUTRAL["king_mrgl-mrgl"].lore = "Behind King Mrgl-Mrgl’s grand murloc facade lies a simple night elf researcher. Originally a part of a druidic research group, King Mrgl-Mrgl has grown far beyond his humble beginnings. After disguising himself as a murloc to observe their populations in Northrend, Mrgl-Mrgl was revered by the creatures and chosen as their king. Though originally reluctant, he accepted the role and never looked back. Ever since, King Mrgl-Mrgl has been found aiding the murlocs of Azeroth and protecting them from outside threats."
IMAGOdb.npcs.CAT_NEUTRAL["king_mrgl-mrgl"].zones = {"Zul'Aman"}
IMAGOdb.npcs.CAT_NEUTRAL["king_mrgl-mrgl"].source = "austin - IMAGO Community"
IMAGOdb.npcs.CAT_NEUTRAL["king_mrgl-mrgl"].timeline = {
    {era = "WotLK", text = "Joined the D.E.H.T.A. expedition group in the Borean Tundra and began his research into murlocs using his unorthodox disguise. The murlocs chose him to be their king in a time of strife; King Mrgl-Mrgl defended the helpless tribe and cemented his place as king."},
    {era = "Legion", text = "Alongside the young murloc hero Murky, King Mrgl-Mrgl attempted to turn the Swamprock murlocs of Highmountain from their violent ways. With the king’s help, Murky was able to establish himself as the more peaceful leader of his new “Murkloc” tribe."},
    {era = "BfA", text = "King Mrgl-Mrgl can be found in Nazjatar as the proprietor of Mrgl’s Bar and Grill, an establishment catering exclusively to the murlocs of the area."},
    {era = "Midnight", text = "After defending the murlocs of Zul’Aman from an attacking tribe of deep sea murlocs, King Mrgl-Mrgl was declared the Loa of Murlocs. His worshippers kept him trapped in their swamp-bound temple as their god and savior."},
}

IMAGOdb.npcs.CAT_NEUTRAL["monte_gazlowe"].name = "Trade Prince Monte Gazlowe"
IMAGOdb.npcs.CAT_NEUTRAL["monte_gazlowe"].race = "Goblin"
IMAGOdb.npcs.CAT_NEUTRAL["monte_gazlowe"].lore = "Monte Gazlowe is one of Azeroth's most brilliant engineers and has had a meteoric career. Once the neutral boss of Ratchet and builder of Orgrimmar, he succeeded Jastor Gallywix after the latter's betrayal. Today, he is the Trade Prince of the Bilgewater Cartel and represents the goblins on the Horde Council. In The War Within, he proved true leadership by leading the expedition deep into Undermine to dismantle Gallywix's Black Blood syndicate and instigating a revolution against the corrupt cartels. In Midnight, he brings his brilliant engineering to the fronts of Harandar and The Den to equip the defensive lines of the united forces with massive goblin firepower."
IMAGOdb.npcs.CAT_NEUTRAL["monte_gazlowe"].zones = {"The Den", "Harandar"}
IMAGOdb.npcs.CAT_NEUTRAL["monte_gazlowe"].source = "warcraft.wiki.gg/wiki/Monte_Gazlowe"
IMAGOdb.npcs.CAT_NEUTRAL["monte_gazlowe"].timeline = {
    {era = "WC3", text = "Worked as a freelance contractor for Thrall and oversaw the construction of the capital city Orgrimmar as chief engineer."},
    {era = "BfA", text = "Took over leadership of the Bilgewater Cartel following Gallywix's flight, firmly integrating the goblins into the Horde Council."},
    {era = "WoD", text = "Served as the architect for the construction of the Horde garrison (Frostwall) on alternate Draenor."},
    {era = "TWW", text = "Led forces to Undermine in Patch 11.1 to stop the exploitation by Gallywix and Xal'atath."},
    {era = "Midnight", text = "Establishes heavily armed technical outposts in Harandar and The Den for military support."},
}

IMAGOdb.npcs.CAT_NEUTRAL["fiona"].name = "Fiona"
IMAGOdb.npcs.CAT_NEUTRAL["fiona"].race = "Worgen"
IMAGOdb.npcs.CAT_NEUTRAL["fiona"].lore = "Fiona is a worgen adventurer, holy priest, and one of the most loyal souls in Azeroth. She became famous for her legendary caravan in the Eastern Plaguelands, with which she safely escorted countless adventurers—most notably her best friends, the paladins Gidwin Goldbraids and Tarenar Sunstrike—through enemy territory. She is the personified lifeblood of civilians and independent helpers in Azeroth. In Midnight, she has steered her caravan to the Isle of Quel'Danas. Although she belongs to no military order, she tirelessly supports the defenders of the Light with her healing arts, her supplies, and her pragmatism."
IMAGOdb.npcs.CAT_NEUTRAL["fiona"].zones = {"Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_NEUTRAL["fiona"].source = "warcraft.wiki.gg/wiki/Fiona"
IMAGOdb.npcs.CAT_NEUTRAL["fiona"].timeline = {
    {era = "Cata", text = "Drove her famous caravan through the Eastern Plaguelands and supported the Argent Crusade."},
    {era = "WoD", text = "Joined the Alliance expedition on Draenor, serving as a holy priest and herbalist in the garrison (Shadowmoon Valley)."},
    {era = "DF", text = "Traveled with the Dragonscale Expedition to the Waking Shores basecamp after reuniting with Gidwin and Tarenar."},
    {era = "Midnight", text = "Appears on the Isle of Quel'Danas as a civilian supporter and healer for the united defenders against the Void."},
}

IMAGOdb.npcs.CAT_NEUTRAL["valeera_sanguinar"].name = "Valeera Sanguinar"
IMAGOdb.npcs.CAT_NEUTRAL["valeera_sanguinar"].race = "Blood Elf"
IMAGOdb.npcs.CAT_NEUTRAL["valeera_sanguinar"].lore = "Valeera Sanguinar is a master assassin who places loyalty above faction lines. As a former slave and gladiator, she fought in the arena alongside Varian Wrynn and Broll Bearmantle, forging a deep friendship with House Wrynn. For a long time, she battled an addiction to fel magic after absorbing the essence of the dreadlord Kathra'natir to save her friends. In Midnight, she returns to her old homeland of Quel'Thalas. There, she accompanies the heroes of Azeroth as a Delve Companion into the most dangerous vaults and depths to stop the spread of the Void with deadly precision."
IMAGOdb.npcs.CAT_NEUTRAL["valeera_sanguinar"].zones = {"Academic Uproar", "Atal'Aman", "The Grudge Pit", "Harandar", "Den of Masters", "Eversong Woods", "Voidstorm", "Parhelion Plaza", "Silvermoon City", "Zul'Aman"}
IMAGOdb.npcs.CAT_NEUTRAL["valeera_sanguinar"].source = "warcraft.wiki.gg/wiki/Valeera_Sanguinar"
IMAGOdb.npcs.CAT_NEUTRAL["valeera_sanguinar"].timeline = {
    {era = "Pre-WotLK", text = "Fought as a gladiator of the Crimson Ring alongside Lo'Gosh (Varian Wrynn) and Broll Bearmantle."},
    {era = "WotLK", text = "Accompanied Varian Wrynn during the Battle for the Undercity, supporting him as a personal bodyguard."},
    {era = "Legion", text = "Joined the Uncrowned (Rogue Order) in the Hall of Shadows and helped permanently banish the demon Kathra'natir."},
    {era = "BfA", text = "Acted as a secret courier between Anduin Wrynn, Baine Bloodhoof, and Varok Saurfang to undermine Sylvanas' rule."},
    {era = "Midnight", text = "Roams the most dangerous instances and depths of Quel'Thalas as a Delve Companion to combat the Void invasion."},
}

IMAGOdb.npcs.CAT_NEUTRAL["freya"].name = "Freya"
IMAGOdb.npcs.CAT_NEUTRAL["freya"].race = "Titan Keeper"
IMAGOdb.npcs.CAT_NEUTRAL["freya"].lore = "Freya is one of the most powerful Titan Keepers of Azeroth, created by the Pantheon and empowered by Eonar to shape and protect life on the planet. It was she who channeled the Emerald Dream and planted the first seeds from which the great World Trees grew. After being corrupted by the Old God Yogg-Saron in Ulduar and freed by adventurers, she largely withdrew. In Midnight, however, she intervenes directly: Harandar harbors an ancient, bioluminescent ecosystem and the delicate roots that ensure the survival of life itself. Freya steps out of the shadows of history to defend this pristine jungle as an uncompromising guardian against the all-consuming hunger of the Void."
IMAGOdb.npcs.CAT_NEUTRAL["freya"].zones = {"Harandar"}
IMAGOdb.npcs.CAT_NEUTRAL["freya"].source = "warcraft.wiki.gg/wiki/Freya"
IMAGOdb.npcs.CAT_NEUTRAL["freya"].timeline = {
    {era = "Ancient", text = "Shaped the Emerald Dream and created the first refuges of life (such as Un'Goro Crater, Sholazar Basin, and the Vale of Eternal Blossoms)."},
    {era = "WotLK", text = "Was driven to madness by Yogg-Saron in Ulduar until Azeroth's heroes defeated her and cleansed her of the corruption."},
    {era = "Midnight", text = "Personally watches over the pristine jungle of Harandar to prevent the spread of the Void into the fragile ecosystem."},
}


-- CAT_EBON_BLADE
IMAGOdb.npcs.CAT_EBON_BLADE["darion_mograine"].name = "Highlord Darion Mograine"
IMAGOdb.npcs.CAT_EBON_BLADE["darion_mograine"].race = "Human"
IMAGOdb.npcs.CAT_EBON_BLADE["darion_mograine"].lore =
[[
Darion Mograine was a paladin of the Argent Dawn who, after sacrificing his life to save the soul of his father, was resurrected as a Death Knight to serve as one of the Lich King’s most powerful commanders. Breaking free from the Lich King’s control at the Battle for Light’s Hope Chapel, he founded the Ebon Blade, a band of Death Knights committed to protecting Azeroth from any threats that come her way.

Now leading the Four Horsemen, Darion defends the home of the Argent Crusade from the Scourge whilst they assist Azeroth’s champion with the destruction of the Devouring Host.]]
IMAGOdb.npcs.CAT_EBON_BLADE["darion_mograine"].zones = {"Eastern Plaguelands"}
IMAGOdb.npcs.CAT_EBON_BLADE["darion_mograine"].source = "Nebb - IMAGO Community"
IMAGOdb.npcs.CAT_EBON_BLADE["darion_mograine"].timeline = {
    {era = "WC3", text = "Joined the Silver Hand and assisted with fighting the Scourge."},
    {era = "Classic", text = "Enlisted the aid of the Argent Dawn to attack Naxxramas, reclaiming the Ashbringer from his undead Father after defeating the Four Horsemen. Sacrificed himself to save the Argent Dawn, and was resurrected as a Death Knight."},
    {era = "WotLK", text = "Made the ruler of the Death Knights of Acherus. Broke free from the Lich King’s control and started the Ebon Blade. Assisted in the war against the scourge in Icecrown and Zul’Drak. Helped to defeat the Lich King at Icecrown Citadel. Found that Bolvar Fordragon has been crowned the new Lich King."},
    {era = "WoD", text = "Journeyed to alternate Draenor to attempt to discover Ner’zhul’s secrets in an attempt to save Bolvar."},
    {era = "Legion", text = "Aided Bolvar and the chosen Death Knight in resurrecting the new Four Horsemen. Was fatally wounded when attempting to resurrect Tirion Fordring, but was raised by Bolvar to lead the horsemen."},
    {era = "BfA", text = "Gathered fallen champions of the Horde and Alliance to be raised as the next generation of Death Knights. Personally sent the new generation to their faction’s capitals."},
    {era = "SL", text = "Stepped down as leader of the Ebon Blade, relinquishing title to Bolvar following the destruction of the Helm of Domination. Summoned the champions of Azeroth to meet with Bolvar and adventure into the Maw. Helped attack the Sanctum of Domination. Returned to Azeroth following the Jailer’s defeat to hold back the Scourge."},
    {era = "Midnight", text = "Defended Light’s Hope Chapel from the Scourge along with the rest of the Four Horsemen."},
}


-- CAT_VOID
IMAGOdb.npcs.CAT_VOID["nexuskoenig_salhadaar"].name = "Nexus-King Salhadaar"
IMAGOdb.npcs.CAT_VOID["nexuskoenig_salhadaar"].race = "Ethereal"
IMAGOdb.npcs.CAT_VOID["nexuskoenig_salhadaar"].lore = "Once the power-hungry leader of the Ethereum in Outland's Netherstorm. Salhadaar attempted to transform his people into pure void energy before being defeated by adventurers. In Midnight, he returns as a fully realized entity of the Void. He now commands forces in the Voidstorm under Xal'atath's banner, serving as living proof of what becomes of the ethereals when they fully surrender to the darkness."
IMAGOdb.npcs.CAT_VOID["nexuskoenig_salhadaar"].zones = {"Voidstorm"}
IMAGOdb.npcs.CAT_VOID["nexuskoenig_salhadaar"].source = "warcraft.wiki.gg/wiki/Nexus-King_Salhadaar"
IMAGOdb.npcs.CAT_VOID["nexuskoenig_salhadaar"].timeline = {
    {era = "TBC", text = "Led the Ethereum in Netherstorm and was killed while attempting to master the energies of the Void."},
    {era = "Midnight", text = "Returns as a powerful Void entity in the Voidstorm to carry out Xal'atath's orders."},
}

IMAGOdb.npcs.CAT_VOID["l_ura"].name = "L'ura"
IMAGOdb.npcs.CAT_VOID["l_ura"].race = "Void Naaru"
IMAGOdb.npcs.CAT_VOID["l_ura"].lore = "L'ura is the tragic centerpiece of the Void invasion in Quel'Thalas. Once a being of Light who covered the draenei's flight from Argus, she fell into a Void state after eons of imprisonment. After Alleria Windrunner absorbed her essence in the Seat of the Triumvirate, L'ura served as the source of Alleria's Void power for years. In Midnight, her fate reaches a horrific climax: Xal'atath stabbed Alleria in the back at the Voidspire and forcibly tore L'ura's essence from her. With this power, the Harbinger corrupted the Sunwell into the 'Darkwell.' Serving as the final encounter during the March on Quel'Danas, L'ura must be defeated once and for all to prevent the total transformation of the well into a font of absolute darkness."
IMAGOdb.npcs.CAT_VOID["l_ura"].zones = {"Isle of Quel'Danas"}
IMAGOdb.npcs.CAT_VOID["l_ura"].source = "warcraft.wiki.gg/wiki/L'ura"
IMAGOdb.npcs.CAT_VOID["l_ura"].timeline = {
    {era = "Ancient", text = "Stayed behind during the flight from Argus to hold back the Legion and was imprisoned in the Seat of the Triumvirate on Kil'jaeden's orders."},
    {era = "Legion", text = "Was defeated by Alleria Windrunner and adventurers, with Alleria fully siphoning her essence."},
    {era = "Midnight", text = "Manifested by Alleria in the Voidstorm to defeat the naaru T'era. Later torn from Alleria by Xal'atath at the Voidspire to transform the Sunwell into the 'Darkwell'."},
    {era = "Midnight", text = "Serves as the final encounter in the 'March on Quel'Danas' to prevent the salvation of the Sunwell."},
}


-- CAT_AMANI
IMAGOdb.npcs.CAT_AMANI["zaljarra"].name = "Zul'jarra"
IMAGOdb.npcs.CAT_AMANI["zaljarra"].race = "Forest Troll"
IMAGOdb.npcs.CAT_AMANI["zaljarra"].lore =
[[
The eldest of two siblings, Zul'jarra was raised a warrior. The grand-daughter of the infamous Zul'jin, she was taught the traditional ways to revere the loa and to lead her future clan with honor. The time to lead came sooner than anyone would have expected, for she was merely a child when both her grandfather and her father were slain in the temple city of Zul-Aman. Deemed too young to rule, this left her mother, Zarama, to rule the Amani for decades. When a crippled Zarama eventually tried to pass the title to her daughter, a rival chieftain challenged Zul'jarra's right to rule. Delayed in her return to the duel, Zul'jarra arrived only to watch her mother fall in her place, forcing her to avenge Zarama and claim her birthright in blood.

Now years later, she attempts to finally reconnect the tribes of Zul'Aman to the loa gods, supported, though occasionally opposed, by her brother, Zul'jan.]]
IMAGOdb.npcs.CAT_AMANI["zaljarra"].zones = {"Atal'Aman", "The Heart of Rage", "Eversong Woods", "Isle of Quel'Danas", "Den of Nalorakk", "Zul'Aman"}
IMAGOdb.npcs.CAT_AMANI["zaljarra"].source = "Cadash - IMAGO Community"
IMAGOdb.npcs.CAT_AMANI["zaljarra"].timeline = {
    {era = "TBC", text = "Lost her father Man'ye and grandfather Zul'jin when she was just a young child. Later, her mother was killed in ritual combat. After avenging her, Zul'jarra took her rightful place as the new leader."},
    {era = "Midnight", text = "Chose to ally with Lady Liadrin and accept her help in becoming hash'ey. Zul'jarra united the tribes of Zul'Aman and regained the trust of the loa. Afterwards she led the battle against the Twilight's Blade, successfully defending her people from the Void."},
}

IMAGOdb.npcs.CAT_AMANI["nalorakk"].name = "Nalorakk"
IMAGOdb.npcs.CAT_AMANI["nalorakk"].race = "Forest Troll"
IMAGOdb.npcs.CAT_AMANI["nalorakk"].lore = "Once a proud forest troll, Nalorakk was infused with the essence of the bear god Rhunok through the dark magic of Hex Lord Malacrass. He served as the brutal guardian and first loa avatar in classic Zul'Aman before being struck down by adventurers. In Midnight, the massive bear avatar mysteriously manifests once again. With sheer physical force and animalistic fury, he joins the Amani to defend the Heart of Rage against the Void."
IMAGOdb.npcs.CAT_AMANI["nalorakk"].zones = {"Heart of Rage", "Nalorakk's Den", "Zul'Aman"}
IMAGOdb.npcs.CAT_AMANI["nalorakk"].source = "warcraft.wiki.gg/wiki/Nalorakk"
IMAGOdb.npcs.CAT_AMANI["nalorakk"].timeline = {
    {era = "TBC", text = "Became the avatar of the bear god Rhunok through Malacrass and guarded the entrance of Zul'Aman as its first boss."},
    {era = "Midnight", text = "Returns to Nalorakk's Den, unleashing the power of the bear against Xal'atath's invading forces."},
}

IMAGOdb.npcs.CAT_AMANI["akilzon"].name = "Akil'zon"
IMAGOdb.npcs.CAT_AMANI["akilzon"].race = "Forest Troll"
IMAGOdb.npcs.CAT_AMANI["akilzon"].lore = "Akil'zon was once a mighty warrior of the Amani before Hex Lord Malacrass used dark magic to transform him into the avatar of the eagle god Akil'darac. In classic Zul'Aman, he commanded the storms until adventurers put an end to his reign. In Midnight, the eagle avatar manifests once again in Zul'Aman. Armed with the power of lightning, he takes to the skies to defend his homeland against the Void invaders."
IMAGOdb.npcs.CAT_AMANI["akilzon"].zones = {"Zul'Aman"}
IMAGOdb.npcs.CAT_AMANI["akilzon"].source = "warcraft.wiki.gg/wiki/Akil'zon"
IMAGOdb.npcs.CAT_AMANI["akilzon"].timeline = {
    {era = "TBC", text = "Became the eagle avatar through dark rituals and ruled the peak of the Amani as the second boss in Zul'Aman."},
    {era = "Midnight", text = "Returns to Zul'Aman to unleash the power of the storms against Xal'atath's forces."},
}

IMAGOdb.npcs.CAT_AMANI["janalai"].name = "Jan'alai"
IMAGOdb.npcs.CAT_AMANI["janalai"].race = "Forest Troll"
IMAGOdb.npcs.CAT_AMANI["janalai"].lore = "Before Hex Lord Malacrass used dark magic to elevate him to the avatar of the dragonhawk god, Jan'alai was a gifted troll of the Amani. In classic Zul'Aman, he wielded blazing fire and summoned countless dragonhawks to turn intruders to ash. In Midnight, the flaming avatar miraculously manifests once again in Zul'Aman. With cleansing flames and relentless heat, he defends his tribe's territory against the cold shadows of the Void."
IMAGOdb.npcs.CAT_AMANI["janalai"].zones = {"Zul'Aman"}
IMAGOdb.npcs.CAT_AMANI["janalai"].source = "warcraft.wiki.gg/wiki/Jan'alai"
IMAGOdb.npcs.CAT_AMANI["janalai"].timeline = {
    {era = "TBC", text = "Became the avatar of the dragonhawk through Malacrass and guarded Zul'Aman with fire and flying beasts."},
    {era = "Midnight", text = "Returns to Zul'Aman as a burning protector to repel the Void invasion with fire."},
}

IMAGOdb.npcs.CAT_AMANI["halazzi"].name = "Halazzi"
IMAGOdb.npcs.CAT_AMANI["halazzi"].race = "Forest Troll"
IMAGOdb.npcs.CAT_AMANI["halazzi"].lore = "Halazzi was a proud forest troll before Hex Lord Malacrass's dark rituals elevated him to the avatar of the lynx god Shirvallah. In classic Zul'Aman, he embodied the wild, relentless hunt and was known for his lightning-fast, deadly ambush strikes. In Midnight, the circle is completed: the lynx avatar manifests once again in the ancient ruins of Zul'Aman. Fierce and patient as ever, he lurks in the shadows, ready to tear the forces of the Void to pieces."
IMAGOdb.npcs.CAT_AMANI["halazzi"].zones = {"Zul'Aman"}
IMAGOdb.npcs.CAT_AMANI["halazzi"].source = "warcraft.wiki.gg/wiki/Halazzi"
IMAGOdb.npcs.CAT_AMANI["halazzi"].timeline = {
    {era = "TBC", text = "Became the lynx avatar of Shirvallah through Malacrass and lurked as a brutal boss in Zul'Aman, waiting for intruders."},
    {era = "Midnight", text = "Manifests again in Zul'Aman to hunt the servants of the Void with the cunning and ferocity of the lynx."},
}

IMAGOdb.npcs.CAT_AMANI["zuljan"].name = "Zul'jan"
IMAGOdb.npcs.CAT_AMANI["zuljan"].race = "Forest Troll"
IMAGOdb.npcs.CAT_AMANI["zuljan"].lore = "As one of the most prominent Amani leaders in Midnight, Zul'jan stands firmly alongside Zul'jarra. He embodies the deep shamanic tradition of the tribe and maintains the vital connection to the loa powers. His constant presence on the most heated fronts in Zul'Aman and Eversong Woods shows that he plays an absolute key role in coordinating the troops and the spiritual defense against the Void."
IMAGOdb.npcs.CAT_AMANI["zuljan"].zones = {"Atal'Aman", "Eversong Woods", "Zul'Aman"}
IMAGOdb.npcs.CAT_AMANI["zuljan"].source = "warcraft.wiki.gg/wiki/Zul'jan"
IMAGOdb.npcs.CAT_AMANI["zuljan"].timeline = {
    {era = "Midnight", text = "Emerges as a high-ranking Amani leader, supporting Zul'jarra in the defense and coordination of the tribe."},
}

IMAGOdb.npcs.CAT_AMANI["loa_speaker_kinduru"].name = "Loa Speaker Kinduru"
IMAGOdb.npcs.CAT_AMANI["loa_speaker_kinduru"].race = "Forest Troll (Amani)"
IMAGOdb.npcs.CAT_AMANI["loa_speaker_kinduru"].lore = "Loa Speaker Kinduru is the eccentric yet endearing spiritual guide of the Amani. As the direct son of the legendary Zul'jin and uncle to Zul'jan and Zul'jarra, he forms a massive contrast to his warmongering bloodline. While his nephew Zul'jan rejects faith in the Loa, Kinduru is a devout servant of the mighty Amani gods—Akil'zon, Halazzi, Jan'alai, and Nalorakk. His personality reminds many of a wise, slightly mad shaman. In Midnight, he is the driving spiritual force in Zul'Aman. He patiently teaches the defenders how to earn the blessings of the Loa to stave off the endless hunger of the Void."
IMAGOdb.npcs.CAT_AMANI["loa_speaker_kinduru"].zones = {"Atal'Aman", "Zul'Aman"}
IMAGOdb.npcs.CAT_AMANI["loa_speaker_kinduru"].source = "warcraft.wiki.gg/wiki/Loa_Speaker_Kinduru"
IMAGOdb.npcs.CAT_AMANI["loa_speaker_kinduru"].timeline = {
    {era = "Pre-MN", text = "Grew up in the shadow of his father Zul'jin, but dedicated his life to the spiritual worship of the Loa instead of blind hatred."},
    {era = "Midnight", text = "Acts as Loa Speaker in Zul'Aman and teaches players at the Altar of Blessings how to harness the gods' power against the Void."},
}


-- CAT_HARATI
IMAGOdb.npcs.CAT_HARATI["orweyna"].name = "Orweyna"
IMAGOdb.npcs.CAT_HARATI["orweyna"].race = "Haran'ir"
IMAGOdb.npcs.CAT_HARATI["orweyna"].lore =
[[
A scout of the mysterious race called Haranir, Orweyna is quite different from most of her kind. Fascinated with the world and its people outside of her homeland, she went against her oaths of secrecy and seclusion and made contact first with the champion of Azeroth in Azj-Kahet, and now with the elves of Quel'Thalas to petition their aid.
    
She has a special connection to her goddess, Aln'hara, receiving visions of impending dangers from her that resemble the Radiant Song, and she knows that the Void that threatens Aln'hara will require more than the forces of the Haranir to vanquish.]]
IMAGOdb.npcs.CAT_HARATI["orweyna"].zones = {"The Blinding Vale", "The Den", "Harandar", "Eversong Woods", "Isle of Quel'Danas", "Silvermoon City"}
IMAGOdb.npcs.CAT_HARATI["orweyna"].source = "Cadash - IMAGO Community"
IMAGOdb.npcs.CAT_HARATI["orweyna"].timeline = {
    {era = "Pre-BfA", text = "Noticed the threat of the Black blood in Azj-Kahet and ventured outside of Harandar for the first time to combat the spread."},
    {era = "TWW", text = "Rescued Alleria's and Faerin's expedition in Azj-Kahet from the Nerubians. Kept investigating the Black Blood, following it to Undermine and consequently aided Gazlowe in his rebellion against Gallywix."},
    {era = "Midnight", text = "Helped to contain the Lightbloom in both Harandar and Quel'Thalas. Negotiated a tentative Alliance between her people and the elves of Quel'Thalas, leading the Haranir to explore the outside world for the first time."},
}

IMAGOdb.npcs.CAT_HARATI["elder_hagar"].name = "Elder Hagar"
IMAGOdb.npcs.CAT_HARATI["elder_hagar"].race = "Haran'ir"
IMAGOdb.npcs.CAT_HARATI["elder_hagar"].lore = "Elder Hagar is a deeply revered sage of the Haran'ir and serves in Midnight as the essential diplomatic bridge between the Hara'ti faction and the peoples of Azeroth. Her personal fate is marked by deep tragedy: she once served unnoticed as the Rootwarden for the World Tree Teldrassil. When the tree burned, Hagar experienced the death of its roots deep underground as a deafening, traumatizing silence. Now, with the Void threatening the ancient arcane roots beneath Quel'Thalas, she refuses to stand by and accept the death of another tree. She has left the protective darkness of the underground and positioned herself in Silvermoon City right by the Harandar portal to recruit capable heroes and officially lead her people into the global conflict as an Allied Race."
IMAGOdb.npcs.CAT_HARATI["elder_hagar"].zones = {"The Den", "Harandar", "Eversong Woods", "Silvermoon City"}
IMAGOdb.npcs.CAT_HARATI["elder_hagar"].source = "warcraft.wiki.gg/wiki/Hagar"
IMAGOdb.npcs.CAT_HARATI["elder_hagar"].timeline = {
    {era = "BfA", text = "Watched over the roots of Teldrassil deep underground as a Rootwarden until the tree was destroyed."},
    {era = "Midnight", text = "Coordinates the diplomatic binding and the unlock of the Haran'ir as an Allied Race from Silvermoon City."},
}

IMAGOdb.npcs.CAT_HARATI["amarakk"].name = "Amarakk"
IMAGOdb.npcs.CAT_HARATI["amarakk"].race = "Haran'ir"
IMAGOdb.npcs.CAT_HARATI["amarakk"].lore = "Amarakk is Orweyna's closest confidant and lifelong friend. As the two grew from seed to sapling in the wilds of Harandar, he was always at her side. While Orweyna was always driven by wilder impulses, Amarakk served as the steady voice of reason, her most important counterweight and emotional anchor. Even though surviving underground was harsh, their bond was unbreakable. In Midnight, he remains steadfastly by Orweyna's side as she leads the newly formed Hara'ti faction on the surface. He provides crucial support with his profound knowledge—such as preparing Alndust—to heal the fighters. Amarakk does not shy away from highly dangerous locations like the Dream Rift to aid his friend and his people in the fight against the Void."
IMAGOdb.npcs.CAT_HARATI["amarakk"].zones = {"The Dream Rift", "Harandar"}
IMAGOdb.npcs.CAT_HARATI["amarakk"].source = "Kurzgeschichte: Nach uns, die Stille"
IMAGOdb.npcs.CAT_HARATI["amarakk"].timeline = {
    {era = "Pre-MN", text = "Grew up alongside Orweyna in Harandar, serving as the steady voice of reason to help ground her impulsive nature."},
    {era = "Midnight", text = "Accompanies Orweyna on the surface and in the Dream Rift, supporting the Hara'ti with his knowledge of nature and Alndust."},
}

